        public static void updateManaulAttLog(ViewModels.ManualAttendance obj, string empCode)
        {
            using (var db = new Context())
            {
                string Ecode = "-";
                int id = Convert.ToInt32(obj.employee_code);
                var code = db.employee.Where(e => e.EmployeeId == id).FirstOrDefault();
                if (code != null)
                {
                    Ecode = code.employee_code;
                }


                DLL.Models.ManualAttLog auditTrail = new DLL.Models.ManualAttLog()
                {

                    WhoMark = empCode,
                    WhoseMark = Ecode,
                    FromDate = obj.time_in_from.ToString(),
                    ToDate = obj.time_in_to.ToString(),
                    Remarks = obj.remarks

                };
                db.manAttLog.Add(auditTrail);
                db.SaveChanges();
            }
        }


    }

    public class ReportPermissionAccess
    {
        public static bool GetReportAccessByCode(string strEmpCode, int iReportCode)
        {
            bool allowed = false;

            using (Context db = new Context())
            {
                if (iReportCode == 1)
                {
                    var rptPermission = db.permission_report.Where(p => p.employee_code == strEmpCode && p.prep_01 == true).FirstOrDefault();
                    if (rptPermission != null)
                    {
                        allowed = true;
                    }
                }
                else if (iReportCode == 2)
                {
                    var rptPermission = db.permission_report.Where(p => p.employee_code == strEmpCode && p.prep_02 == true).FirstOrDefault();
                    if (rptPermission != null)
                    {
                        allowed = true;
                    }
                }
                else if (iReportCode == 3)
                {
                    var rptPermission = db.permission_report.Where(p => p.employee_code == strEmpCode && p.prep_03 == true).FirstOrDefault();
                    if (rptPermission != null)
                    {
                        allowed = true;
                    }
                }
                else if (iReportCode == 4)
                {
                    var rptPermission = db.permission_report.Where(p => p.employee_code == strEmpCode && p.prep_04 == true).FirstOrDefault();
                    if (rptPermission != null)
                    {
                        allowed = true;
                    }
                }
                else
                {
                    allowed = false;
                }
            }

            return allowed;
        }
    }


    public class EmployeeFunction
    {

        public static int add(ViewModels.Function fromForm)
        {
            DLL.Models.Function newFunction = new DLL.Models.Function()
            {
                name = fromForm.name.ToLower(),
                description = fromForm.description.ToLower(),
                active = true
            };

            using (Context db = new Context())
            {
                db.function.Add(newFunction);
                db.SaveChanges();
            }
            return newFunction.FunctionId;
        }

        public static List<ViewModels.Function> getAll()
        {
            using (Context db = new Context())
            {
                List<Function> functions = null;
                try
                {
                    functions = db.function.Where(m => m.active).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    functions = new List<Function>();
                }



                List<ViewModels.Function> toReturn = new List<ViewModels.Function>();

                for (int i = 0; i < functions.Count(); i++)
                {
                    toReturn.Add(new ViewModels.Function()
                    {
                        id = functions[i].FunctionId,
                        name = functions[i].name,
                        description = functions[i].description,
                        actions =
                            "<div data-row='" + functions[i].FunctionId + "'>" +
                                "<a href=\"javascript:void(editFunction(" + functions[i].FunctionId + ",'" + functions[i].name + "','" + functions[i].description + "'));\">Edit</a>" +
                                "<span> / </span>" +
                                "<a href=\"javascript:void(deleteFunction(" + functions[i].FunctionId + "));\">Delete</a>" +
                            "</div>"
                    });
                }

                return toReturn;
            }
        }

        public static ViewModels.Function get(int primaryKey)
        {
            using (Context db = new Context())
            {
                Function temp = db.function.Where(m => m.FunctionId.Equals(primaryKey) && m.active).SingleOrDefault();

                ViewModels.Function toReturn = new ViewModels.Function();
                toReturn.id = temp.FunctionId;
                toReturn.name = temp.name;
                toReturn.description = temp.description;

                return toReturn;
            }
        }

        public static void update(ViewModels.Function toUpdate)
        {

            using (Context db = new Context())
            {
                Function toUpdateModel = db.function.Find(toUpdate.id);
                toUpdateModel.name = toUpdate.name.ToLower();
                toUpdateModel.description = toUpdate.description.ToLower();

                db.SaveChanges();
            }

        }

        public static ViewModels.Function remove(ViewModels.Function toRemove)
        {

            using (Context db = new Context())
            {
                Function toRemoveModel = db.function.Find(toRemove.id);
                toRemoveModel.active = false;
                db.SaveChanges();
                toRemove.description = toRemoveModel.description;
                toRemove.name = toRemoveModel.name;
                return toRemove;
            }

        }

    }

