    public class Unis_User
    {
        private static List<tUser> LoadUnisUsersAdo(string connectionString)
        {
            List<tUser> users = new List<tUser>();

            const string sql = "SELECT [user_id], [name], [unique_id] " +
                               "FROM [UCDB].[dbo].[users] " +
                               "WHERE ISNULL([name], '') <> '' AND ISNULL([unique_id], '') <> ''";

            using (SqlConnection conn = new SqlConnection(connectionString))
            using (SqlCommand cmd = new SqlCommand(sql, conn))
            {
                conn.Open();
                using (SqlDataReader reader = cmd.ExecuteReader())
                {
                    int idxId = reader.GetOrdinal("user_id");
                    int idxName = reader.GetOrdinal("name");
                    int idxUnique = reader.GetOrdinal("unique_id");

                    while (reader.Read())
                    {
                        users.Add(new tUser
                        {
                            L_ID = reader.IsDBNull(idxId) ? 0 : Convert.ToInt64(reader.GetValue(idxId)),
                            C_Name = reader.IsDBNull(idxName) ? string.Empty : reader.GetString(idxName),
                            C_Unique = reader.IsDBNull(idxUnique) ? string.Empty : reader.GetString(idxUnique)
                        });
                    }
                }
            }

            return users;
        }

