        }

        public static List<ViewModels.UnisUser> getAllUsersFromBothServer()
        {
            List<ViewModels.UnisUser> toReturn = new List<ViewModels.UnisUser>();
            List<tUser> unisUser1 = new List<tUser>();
            List<tUser> unisUser2 = new List<tUser>();
            //List<tUser> unisUserUniques1 = new List<tUser>();
            //List<tUser> unisUserUniques2 = new List<tUser>();
            List<tUser> unisUserUniques = new List<tUser>();
            List<Employee> empData = null;

            //Employees List
            using (Context db = new Context())
            {
                try
                {
                    empData = db.employee.Where(m => m.employee_code != "").ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    empData = new List<Employee>();
                }
            }

            ///// Server 1 - users
            try
            {
                unisUser1 = LoadUnisUsersAdo(UNISContext.connectionString);
            }
            catch (Exception)
            {
                unisUser1 = new List<tUser>();
            }

            ///// Server 2 - users
            try
            {
                unisUser2 = LoadUnisUsersAdo(UNISContextR2.connectionStringR2);
            }
            catch (Exception)
            {
                unisUser2 = new List<tUser>();
            }

            //merge both servers data - unique only
            if (unisUser1 != null && unisUser1.Count > 0 && unisUser2 != null && unisUser2.Count > 0)
            {
                unisUserUniques = unisUser1.ToList();

                foreach (var u2 in unisUser2)
                {
                    if (unisUserUniques.Where(r => r.C_Unique == u2.C_Unique).FirstOrDefault() == null)//if (result.Where(r => r.L_ID == r2.L_ID && r.C_Name.ToLower() == r2.C_Name.ToLower()).FirstOrDefault() == null)//
                    {
                        unisUserUniques.Add(u2);
                    }
                }
            }
            else
            {
                if (unisUser1 != null && unisUser1.Count > 0)
                    unisUserUniques = unisUser1.ToList();

                if (unisUser2 != null && unisUser2.Count > 0)
                    unisUserUniques = unisUser2.ToList();
            }

            //elimainate unique-employees from trms-employees list
            if (unisUserUniques != null && unisUserUniques.Count > 0)
            {
                var result = unisUserUniques.Where(u => empData.All(e => e.employee_code != u.C_Unique)).ToList();
                for (int i = 0; i < result.Count(); i++)
                {
                    toReturn.Add(new ViewModels.UnisUser()
                    {
                        id = result[i].L_ID,
                        name = result[i].C_Name ?? "",
                        empCode = result[i].C_Unique,
                        actions =
                            "<div data-row='" + result[i].L_ID + "' class='checkbox checkbox-success'>" +
                                "<input type='checkbox' id='" + result[i].L_ID + "' onclick=\"toggle(" + result[i].L_ID + ",'" + result[i].C_Unique + "','" + result[i].C_Name + "');\">" +
                                 "<label for='" + result[i].L_ID + "'></label>" +
                            "</div>"

                    });
                }
            }
            else
            {

            }

            toReturn = toReturn.OrderBy(o => o.name).ToList();

            return toReturn;
        }

