        public static int searchEmployees2(string searchValue, string sortOrder, int start, int length, out List<ViewModels.Employee> toReturn)
        {
            //sortOrder = "first_name";
            if (searchValue == "Yes" || searchValue == "No")
                searchValue = null;

            int count = 0;

            //MUQEET Comments: If sort order does not contain any of the allowed // columns, then it must contain the ones that are not allowed. So change sort order to something that is allowed.


            using (Context db = new Context())
            {
                List<DLL.Models.Employee> employee = null;
                try
                {
                    if (searchValue != null && !searchValue.Equals(""))
                    {
                        // query the DB for count.
                        count = db.employee.Where(m => //m.active &&
                        (m.first_name.Contains(searchValue) ||
                        m.last_name.Contains(searchValue) ||
                        m.employee_code.Contains(searchValue) ||
                        ((m.function != null && m.function.name != null) && m.function.name.Contains(searchValue)) ||
                         ((m.department != null && m.department.name != null) && m.department.name.Contains(searchValue)) ||
                          ((m.region != null && m.region.name != null) && m.region.name.Contains(searchValue)) ||
                           ((m.location != null && m.location.name != null) && m.location.name.Contains(searchValue)) ||
                        ((m.designation != null && m.designation.name != null) && m.designation.name.Contains(searchValue)))).Count();

                        // load actual content.
                        if (sortOrder.ToLower().Contains("first_name d"))
                        {
                            employee = db.employee.Where(m => //m.active &&
                            (m.first_name.Contains(searchValue) ||
                            m.last_name.Contains(searchValue) ||
                           m.employee_code.Contains(searchValue) ||
                           ((m.function != null && m.function.name != null) && m.function.name.Contains(searchValue)) ||
                            ((m.department != null && m.department.name != null) && m.department.name.Contains(searchValue)) ||
                             ((m.region != null && m.region.name != null) && m.region.name.Contains(searchValue)) ||
                              ((m.location != null && m.location.name != null) && m.location.name.Contains(searchValue)) ||

                           ((m.designation != null && m.designation.name != null) && m.designation.name.Contains(searchValue))))
                           .OrderByDescending(o => o.first_name).Skip(start).Take(length).ToList();
                        }
                        else if (sortOrder.ToLower().Contains("first_name"))
                        {
                            employee = db.employee.Where(m => //m.active &&
