    public class EmployeeDesignation
    {
        public static int add(ViewModels.Designation fromForm)
        {
            Designation designation = new Designation()
            {
                name = fromForm.name,
                description = fromForm.description,
                active = true
            };

            using (Context db = new Context())
            {
                db.designation.Add(designation);
                db.SaveChanges();
            }
            return fromForm.id;
        }

        public static List<ViewModels.Designation> getAll()
        {
            using (Context db = new Context())
            {
                List<Designation> designation = null;
                try
                {
                    designation = db.designation.Where(m => m.active).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    designation = new List<Designation>();
                }



                List<ViewModels.Designation> toReturn = new List<ViewModels.Designation>();

                for (int i = 0; i < designation.Count(); i++)
                {
                    toReturn.Add(new ViewModels.Designation()
                    {
                        id = designation[i].DesignationId,
                        name = designation[i].name,
                        description = designation[i].description,
                        actions =
                           "<div data-row='" + designation[i].DesignationId + "'>" +
                               "<a href=\"javascript:void(editDesignation(" + designation[i].DesignationId + ",'" + designation[i].name + "','" + designation[i].description + "'));\">Edit</a>" +
                               "<span> / </span>" +
                               "<a href=\"javascript:void(deleteDesignation(" + designation[i].DesignationId + "));\">Delete</a>" +
                           "</div>"
                    });
                }

                return toReturn;
            }
        }

        public static ViewModels.Designation get(int primaryKey)
        {
            using (Context db = new Context())
            {
                Designation temp = db.designation.Where(m => m.DesignationId.Equals(primaryKey) && m.active).SingleOrDefault();

                ViewModels.Designation toReturn = new ViewModels.Designation();
                toReturn.id = temp.DesignationId;
                toReturn.name = temp.name;
                toReturn.description = temp.description;

                return toReturn;
            }
        }

        public static void update(ViewModels.Designation toUpdate)
        {

            using (Context db = new Context())
            {
                Designation toUpdateModel = db.designation.Find(toUpdate.id);
                toUpdateModel.name = toUpdate.name;
                toUpdateModel.description = toUpdate.description;

                db.SaveChanges();
            }

        }

        public static ViewModels.Designation remove(ViewModels.Designation toRemove)
        {

            using (Context db = new Context())
            {
                Designation toRemoveModel = db.designation.Find(toRemove.id);

                toRemoveModel.active = false;

                db.SaveChanges();

                toRemove.name = toRemoveModel.name;

                toRemove.description = toRemoveModel.description;
            }

            return toRemove;
        }

    }

