            using (Context db = new Context())
            {
                List<DLL.Models.OrganizationCampus> list_campuses = null;

                try
                {
                    if (bGVIsSuperHRRole) //alowed to manage all campuses
                    {
                        list_campuses = db.organization_campus.ToList();
                    }
                    else
                    {
                        list_campuses = db.organization_campus.Where(c => c.Id == iGVCampusID).ToList();
                    }


                    if (list_campuses != null && list_campuses.Count > 0)
                    {
                        for (int i = 0; i < list_campuses.Count(); i++)
                        {
                            toReturn.Add(new ViewModels.OrganizationCampusView()
                            {
                                Id = list_campuses[i].Id,
                                CampusCode = list_campuses[i].CampusCode,

                            });
                        }
                    }
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    list_campuses = new List<DLL.Models.OrganizationCampus>();
                }
            }

            return toReturn;
        }

