    public class EmployeeShift
    {
        // convert from db model to view model
        public static ViewModels.Shift convert(Shift model)
        {
            if (model == null)
                return null;


            string name = model.name;
            string earlyTime = model.start_time.AddSeconds(model.early_time).ToString("hh:mm tt");
            string startTime = model.start_time.ToString("hh:mm tt");
            string lateTime = model.start_time.AddSeconds(model.late_time).ToString("hh:mm tt");
            string halfDay = model.start_time.AddSeconds(model.half_day).ToString("hh:mm tt");
            string shiftEnd = model.start_time.AddSeconds(model.shift_end).ToString("hh:mm tt");
            string dayEnd = model.start_time.AddSeconds(model.day_end).ToString("hh:mm tt");
            //TimeSpan result = TimeSpan.FromHours(model.shift_hours);
            //TimeSpan result1 = new TimeSpan(model.shift_hours / 100, model.shift_hours % 100, 0);
            //string fromTimeString = result.ToString("hh':'mm");
            //string fromTimeString1 = result1.ToString("hh':'mm");
            //string hourse = model.start_time.AddSeconds(model.shift_hours).ToString("hh:mm ");
            return new ViewModels.Shift()
            {
                // This is a check for the holiday shift. If the model
                // has 0 limits then it is a sign that the shift is a holiday
                // shift. And since the front end uses -1 to represent holiday shifts
                // we will return -1 instead of the actual shift.
                id = (model.early_time == 0 && model.day_end == 0) ? -1 : model.ShiftId,

                name = model.name,
                early_time = earlyTime,
                start_time = startTime,
                late_time = lateTime,
                half_day = halfDay,
                shift_end = shiftEnd,
                day_end = dayEnd
                //shift_hours= fromTimeString1
            };
        }

        // helper
        private static int[] validateShift(ViewModels.Shift viewModel)
        {

            string[] allPossibleMinutes = new string[24 * 60];

            int ind = 0;
            for (int i = 0; i <= 23; i++)
            {
                for (int j = 0; j <= 59; j++)
                {
                    string x = new DateTime(1, 1, 1, i, j, 0).ToString("HHmm");
                    allPossibleMinutes[ind++] = (x);
                }
            }

            string startTime = DateTime.Parse("01/01/1990 " + viewModel.start_time).ToString("HHmm");
            string earlyTime = DateTime.Parse("01/01/1990 " + viewModel.early_time).ToString("HHmm");
            string lateTime = DateTime.Parse("01/01/1990 " + viewModel.late_time).ToString("HHmm");
            string halfDay = DateTime.Parse("01/01/1990 " + viewModel.half_day).ToString("HHmm");
            string shiftEnd = DateTime.Parse("01/01/1990 " + viewModel.shift_end).ToString("HHmm");
            string dayEnd = DateTime.Parse("01/01/1990 " + viewModel.day_end).ToString("HHmm");
            // string hours= DateTime.Parse("01/01/1990 " + viewModel.shift_hours).ToString("HHmm");

            int index = 0;
            // set the index to that of 
            // the earlyTime in the array.
            for (var i = 0; i < allPossibleMinutes.Length; i++)
            {
                if (allPossibleMinutes[i].Equals(earlyTime))
                {
                    index = i;
                    break;
                }
            }

            // Now that we have the pointer set to 
            // the early time, we will iterate through the
            // list to find out the next time, which is startTime
            // and meanwhile we will count the minutes.
            int totalMinutes = 0;
            while (!allPossibleMinutes[index].Equals(startTime))
            {

                index = (index + 1) % allPossibleMinutes.Length;
                totalMinutes++;
            }
            int earlyToStartMinutes = totalMinutes;



            // Our pointer is now at shiftStart
            // Lets keep iterating to our next time which is
            // lateTime
            while (!allPossibleMinutes[index].Equals(lateTime))
            {
                //console.log()
                index = (index + 1) % allPossibleMinutes.Length;
                totalMinutes++;
            }
            int startToLateMinutes = totalMinutes - earlyToStartMinutes;

            // Our pointer is now at lateTime
            // Lets keep iterating to our next time which is
            // halfDay
            while (!allPossibleMinutes[index].Equals(halfDay))
            {

                index = (index + 1) % allPossibleMinutes.Length;
                totalMinutes++;
            }
            int startToHalfDayMinutes = totalMinutes - earlyToStartMinutes;

            // Our pointer is now at halfDay
            // Lets keep iterating to our next time which is
            // shiftEnd
            while (!allPossibleMinutes[index].Equals(shiftEnd))
            {
                //console.log()
                index = (index + 1) % allPossibleMinutes.Length;
                totalMinutes++;
            }
            int startToShiftEndMinutes = totalMinutes - earlyToStartMinutes;

            // Our pointer is now at shiftEnd
            // Lets keep iterating to our next time which is
            // dayEnd

            while (!allPossibleMinutes[index].Equals(dayEnd))
            {
                //console.log()
                index = (index + 1) % allPossibleMinutes.Length;
                totalMinutes++;
            }
            int startToDayEndMinutes = totalMinutes - earlyToStartMinutes;
            //int totalhours = earlyToStartMinutes + startToShiftEndMinutes;
            //int thours = int.Parse(hours);

            float totalHours = (totalMinutes / 60.0f);
            int[] toReturn =
            {
                (totalHours < 24)?1:0,
                earlyToStartMinutes*60*-1,
                startToLateMinutes*60,
                startToHalfDayMinutes*60,
                startToShiftEndMinutes*60,
                startToDayEndMinutes*60
                //thours
            };

            return toReturn;
        }
        // convert from view model to db model
        public static Shift convert(ViewModels.Shift viewModel)
        {
            // The validateShift function 
            // validates a shift object, and returns
            // an array which holds the following values
            // INDEX    :      VALUE
            //   0      :  0 OR 1 to represent invalid or valid shift respectively.
            //   1      :  number of seconds from start time to early time -ve value
            //   2      :    //          //       //        //  late time
            //   3      :    //          //       //        //  half day
            //   4      :    //          //       //        //  shift end
            //   5      :    //          //       //        //  day end
            int[] values = validateShift(viewModel);

            // return null for invalid shift
            if (values[0] == 0)
                return null;

            if (viewModel == null)
                return null;

            // We have started from 01/01/1990 so that the year for all the times variables is
            // the same.
            DateTime startTime = DateTime.Parse("01/01/1990 " + viewModel.start_time);
            int earlyTime = values[1];
            int lateTime = values[2];
            int halfDay = values[3];
            int shiftEnd = values[4];
            int dayEnd = values[5];
            //int hours = values[6];

            return new DLL.Models.Shift()
            {
                name = viewModel.name,
                early_time = earlyTime,
                start_time = startTime,
                late_time = lateTime,
                half_day = halfDay,
                shift_end = shiftEnd,
                day_end = dayEnd,
                //shift_hours=hours,
                active = true

            };
        }


