        public static bool update(ViewModels.Shift toUpdate)
        {
            DateTime startTime = DateTime.Parse("01/01/1990 " + toUpdate.start_time);
            int earlyTime = (int)(DateTime.Parse("01/01/1990 " + toUpdate.early_time) - startTime).TotalSeconds;
            int lateTime = (int)(DateTime.Parse("01/01/1990 " + toUpdate.late_time) - startTime).TotalSeconds;
            int halfDay = (int)(DateTime.Parse("01/01/1990 " + toUpdate.half_day) - startTime).TotalSeconds;
            int shiftEnd = (int)(DateTime.Parse("01/01/1990 " + toUpdate.shift_end) - startTime).TotalSeconds;
            int dayEnd = (int)(DateTime.Parse("01/01/1990 " + toUpdate.day_end) - startTime).TotalSeconds;
            //string start = toUpdate.start_time;
            //string end = toUpdate.shift_end;
            //TimeSpan duration = DateTime.Parse(end).Subtract(DateTime.Parse(start));
            //String hours = duration.ToString(@"hh\:mm\:ss");
            //toUpdate.shift_hours = hours;
            using (Context db = new Context())
            {
                DLL.Models.Shift toUpdateModel = db.shift.Find(toUpdate.id);

                DLL.Models.Shift dummyModel = convert(toUpdate);
                if (dummyModel == null) // bad values for shift
                {
                    return false;
                }

                toUpdateModel.name = toUpdate.name;
                toUpdateModel.early_time = dummyModel.early_time;
                toUpdateModel.start_time = dummyModel.start_time;
                toUpdateModel.late_time = dummyModel.late_time;
                toUpdateModel.half_day = dummyModel.half_day;
                toUpdateModel.shift_end = dummyModel.shift_end;
                toUpdateModel.day_end = dummyModel.day_end;
                //toUpdateModel.shift_hours = dummyModel.shift_hours;
                toUpdateModel.active = true;

                db.SaveChanges();
            }

            return true;

        }

