                                DateTime dateTime2 = DateTime.ParseExact(TimeOutUser, "hh:mm tt", CultureInfo.InvariantCulture);


                                if (dateTime1.TimeOfDay < dateTime2.TimeOfDay)
                                {
                                    time = TimeSpan.FromSeconds(log.overtime);
                                    OvertimeNew = time.ToString(@"hh\:mm\:ss");

                                }
                                else
                                {
                                    time = TimeSpan.FromSeconds(log.overtime);
                                    OvertimeNew = "-"; // +time.ToString(@"hh\:mm\:ss");
                                }

                            }
                        }
                        else
                        {
                            time = TimeSpan.FromSeconds(log.overtime);
                            OvertimeNew = "-"; // +time.ToString(@"hh\:mm\:ss");
                        }

                        string TotalHours = "-";
                        if (log.time_in != null && log.time_out != null)
                        {
                            TotalHours = log.time_out.Value.Subtract(log.time_in.Value).ToString();
                        }




                        if (log.overtime_status == 1) { OvertimeStatusNew = "Unapproved"; }
                        else if (log.overtime_status == 2) { OvertimeStatusNew = "Approved"; }
                        else if (log.overtime_status == 3) { OvertimeStatusNew = "Discard"; }


                        toReturn.Add(new ViewModels.ConsolidatedAttendanceLog()
                        {
                            id = log.id,
                            date = (log.date.HasValue) ? log.date.Value.ToString("dd-MM-yyyy") : "",
                            employee_code = log.employee_code,
                            employee_first_name = log.employee_first_name,
                            employee_last_name = log.employee_last_name,
                            time_in = (log.time_in.HasValue) ? log.time_in.Value.ToString("hh:mm tt") : "",
                            status_in = log.status_in,
                            time_out = (log.time_out.HasValue) ? log.time_out.Value.ToString("hh:mm tt") : "",
                            status_out = log.status_out,
                            final_remarks = log.final_remarks,
                            terminal_in = log.terminal_in,
                            hours = TotalHours

                        });
                    }
                }


                return count;
            }
        }

        public static int getWorkHourReportAttendance(string employee_id, string from, string to, string search, string sortOrder, int start, int length, out List<ViewModels.ConsolidatedAttendanceLog> toReturn)
        {

            int emp_id;

            if (!int.TryParse(employee_id, out emp_id))
            {
                emp_id = -1;
            }

            string firstDay = null;
            string lastDay = null;

            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {
                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture).ToString("yyyy-MM-dd");
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture).ToString("yyyy-MM-dd");
                }
                catch
                {

                }
            }
            else
            {
                //Added by Inayat 7th Dec 2017
                if (employee_id == null && from == null && to == null)
                {
                    firstDay = DateTime.ParseExact(DateTime.Now.ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture).ToString("yyyy-MM-dd"); ;
                    lastDay = DateTime.ParseExact(DateTime.Now.AddDays(1).ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture).ToString("yyyy-MM-dd"); ;
                }
            }


            using (Context db = new Context())
            {
                string empCode = "";
                if (emp_id != -1)
                {
                    empCode = db.employee.Where(p => p.EmployeeId == emp_id).FirstOrDefault().employee_code;
                }
                int count = 0;
                toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();


                var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediate>();

                try
                {



                    if (employee_id != null)
                    {

                        DateTime? times;
                        string sdd = "";

                        if (search != null && search.Split(':').Count() == 2 && search.Length == 8)
                        {
                            times = DateTime.Parse(search);
                            var pp = times.Value.TimeOfDay.ToString();
                            sdd = pp.Remove(pp.Length - 3);
                        }
                    }


                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();
                }


                if (empCode != null && empCode != "")
                {
                    List<ViewModels.HaTransitsUniqueAttendanceLog> dInLogs = db.Database.SqlQuery<ViewModels.HaTransitsUniqueAttendanceLog>(string.Format("Sp_GetAllDeviceInLogs @EmpCode='{0}' , @toDate='{1}' , @fromDate='{2}'", empCode, firstDay, lastDay)).ToList();

                    List<ViewModels.HaTransitsUniqueAttendanceLog> dOutLogs = db.Database.SqlQuery<ViewModels.HaTransitsUniqueAttendanceLog>(string.Format("Sp_GetAllDeviceOutLogs @EmpCode='{0}' , @toDate='{1}' , @fromDate='{2}'", empCode, firstDay, lastDay)).ToList();

                    DateTime dt = Convert.ToDateTime(firstDay);
                    DateTime Lt = Convert.ToDateTime(lastDay);
                    int daysCount = Convert.ToInt32((Lt - dt).TotalDays) + 1;
                    TimeSpan duration = new TimeSpan();
                    List<ViewModels.HaTransitsUniqueAttendanceLog> deviceInLogs = new List<ViewModels.HaTransitsUniqueAttendanceLog>(); ;


                    DateTime time1, time2;
                    double timeIn_d, timeOut_d, totaltimeDuration = 0.0;


                    if (dInLogs != null && dOutLogs != null && dInLogs.Count > 0 && dOutLogs.Count > 0)
                    {
                        for (int l = 0; l < daysCount; l++)
                        {


                            deviceInLogs = dInLogs.Where(p => p.C_date == dt.AddDays(l)).ToList();
                            var deviceOutLogs = dOutLogs.Where(p => p.C_date == dt.AddDays(l)).ToList();
                            int totalLoop = 0;

                            totalLoop = deviceInLogs.Count < deviceOutLogs.Count ? deviceInLogs.Count : deviceOutLogs.Count;


                            if (deviceInLogs != null && deviceOutLogs != null && deviceInLogs.Count > 0 && deviceOutLogs.Count > 0)
                            {

                                for (int i = 0; i < totalLoop; i++)
                                {
                                    //ViewModels.HaTransitsUniqueAttendanceLog In = getCorrespondingValue(deviceInLogs, i);
                                    //ViewModels.HaTransitsUniqueAttendanceLog Out = getCorrespondingValue(deviceOutLogs, i);


                                    if (deviceInLogs[i].C_Time != null && deviceOutLogs[i].C_Time != null)
                                    {
                                        time1 = Convert.ToDateTime(deviceInLogs[i].C_Time);
                                        time2 = Convert.ToDateTime(deviceOutLogs[i].C_Time);
                                        timeIn_d = Convert.ToDouble(time1.TimeOfDay.TotalMinutes);
                                        timeOut_d = Convert.ToDouble(time2.TimeOfDay.TotalMinutes);
                                        totaltimeDuration += (timeOut_d - timeIn_d);


                                    }
                                }


                            }


                        }


                        foreach (var log in deviceInLogs)
                        {

                            toReturn.Add(new ViewModels.ConsolidatedAttendanceLog()
                            {
                                id = log.HaTransitId,
                                time_in = from.ToString(),
                                time_out = to.ToString(),
                                employee_code = log.C_Unique,
                                employee_first_name = log.Name,
                                final_remarks = TimeSpan.FromMinutes(totaltimeDuration).ToString()


                            });
                            break;

                        }




                    }
                }
            }


            return 0;
        }

        public static ViewModels.HaTransitsUniqueAttendanceLog getCorrespondingValue(List<ViewModels.HaTransitsUniqueAttendanceLog> logs, int i)
        {
            if (logs[i] != null)
                return logs[i];
            else
                return null;
        }


