        public static int getMonthlyOvertimeReportByEmployeeId(string employee_id, string from, string to, string search, string sortOrder, int start, int length, out List<ViewModels.MonthlyTimesheetAttendanceLog> toReturn)
        {
            int emp_id;

            if (sortOrder == null)
            {
                sortOrder = "date desc";
            }

            if (sortOrder.Contains("action"))
            {
                sortOrder = "date desc";
            }

            if (sortOrder.ToLower() == "date desc")
            {
                sortOrder = "date desc";
            }

            if (!int.TryParse(employee_id, out emp_id))
            {
                emp_id = -1;
            }

            DateTime? firstDay = null;
            DateTime? lastDay = null;

            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {
                    if (from == "undefined--undefined" || to == "undefined--undefined")
                    {
                        firstDay = DateTime.ParseExact(DateTime.Now.ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                        lastDay = DateTime.ParseExact(DateTime.Now.AddDays(1).ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    }
                    else
                    {
                        firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                        lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    }
                }
                catch
                {

                }
                /*string[] components = "saf".Split('-');

                int year;
                int mnth;

                if (components.Length == 2)
                {
                    if (int.TryParse(components[0], out year) && int.TryParse(components[1],out mnth))
                    {
                        firstDayOfMonth = new DateTime(year, mnth, 1);
                        lastDayOfMonth = firstDayOfMonth.Value.AddMonths(1).AddDays(-1);
                    }
                }*/

            }
            else
            {
                //Added by Inayat 7th Dec 2017
                if (employee_id == null && from == null && to == null)
                {
                    firstDay = DateTime.ParseExact(DateTime.Now.ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(DateTime.Now.AddDays(1).ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
            }


            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.MonthlyTimesheetAttendanceLog>();


                var temp = new List<ViewModels.MonthlyTimesheetAttendanceLogIntermediate>();

                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    DateTime? times;
                    string sdd = "";
                    if (search != null && search.Split(':').Count() == 2 && search.Length == 8)
                    {
                        times = DateTime.Parse(search);
                        var pp = times.Value.TimeOfDay.ToString();
                        sdd = pp.Remove(pp.Length - 3);
                    }

                    count = db.consolidated_attendance
                        .Where(p => p.active &&
                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.employee.employee_code.Contains(search.ToLower()) ||
                                    p.employee.first_name.Contains(search.ToLower()) ||
                                    p.employee.last_name.Contains(search.ToLower()) ||
                                    p.status_in.Contains(search.ToLower()) ||
                                    p.status_out.Contains(search.ToLower()) ||
                                    p.final_remarks.Contains(search.ToLower()) ||
                                    p.terminal_in.Contains(search.ToLower()) ||
                                    EntityFunctions.TruncateTime(p.date).ToString().Contains(search.ToLower()) ||
                                    EntityFunctions.CreateTime(p.time_in.Value.Hour, p.time_in.Value.Minute, p.time_in.Value.Second).ToString().Contains(sdd.ToLower()) ||
                                    EntityFunctions.CreateTime(p.time_out.Value.Hour, p.time_out.Value.Minute, p.time_out.Value.Second).ToString().Contains(sdd.ToLower()) ||
                                    p.terminal_out.Contains(search.ToLower()))
                                    &&
                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            ).Count();

                    temp = db.consolidated_attendance
                        .Where(p => p.active &&

                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.employee.employee_code.Contains(search.ToLower()) ||
                                    p.employee.first_name.Contains(search.ToLower()) ||
                                    p.employee.last_name.Contains(search.ToLower()) ||
                                    p.status_in.Contains(search.ToLower()) ||
                                    p.status_out.Contains(search.ToLower()) ||
                                    p.final_remarks.Contains(search.ToLower()) ||
                                    p.terminal_in.Contains(search.ToLower()) ||
                                    System.Data.Entity.DbFunctions.TruncateTime(p.date).ToString().Contains(search.ToLower()) ||
                                    System.Data.Entity.DbFunctions.CreateTime(p.time_in.Value.Hour, p.time_in.Value.Minute, p.time_in.Value.Second).ToString().Contains(sdd.ToLower()) ||
                                    System.Data.Entity.DbFunctions.CreateTime(p.time_out.Value.Hour, p.time_out.Value.Minute, p.time_out.Value.Second).ToString().Contains(sdd.ToLower()) ||

                                    p.terminal_out.Contains(search.ToLower()))

                                    &&

                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))


                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            )
                        .Select(p =>
                            new ViewModels.MonthlyTimesheetAttendanceLogIntermediate()
                            {

                                id = p.ConsolidatedAttendanceId,
                                date = p.date,
                                employee_code = p.employee.employee_code,
                                employee_first_name = p.employee.first_name,
                                employee_last_name = p.employee.last_name,
                                time_in = p.time_in,
                                status_in = p.status_in,
                                time_out = p.time_out,
                                status_out = p.status_out,
                                final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks,
                                terminal_in = (p.terminal_in != null) ? p.terminal_in : " ",
                                terminal_out = (p.terminal_out != null) ? p.terminal_out : " ",
                                overtime = p.overtime,
                                overtime_status = p.overtime_status



                            })
                        .SortBy(sortOrder).Skip(start).Take(length).ToList();

                    //count = temp.Count;
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.MonthlyTimesheetAttendanceLog>();
                }

                string OvertimeNew = "";
                string OvertimeStatusNew = "";
                TimeSpan time;
                string startTime2 = "", shiftEnd3 = "";
                if (temp != null)
                {
                    foreach (var log in temp)
                    {
                        int empId = Convert.ToInt32(employee_id);

                        var getGroupId = db.employee.Where(e => e.EmployeeId == emp_id).FirstOrDefault();
                        if (getGroupId != null)
                        {
                            if (getGroupId.Group != null)
                            {
                                if (getGroupId.Group.follows_general_calendar)
                                {
                                    int gC = db.general_calender.Where(s => s.year == DateTime.Now.Year).FirstOrDefault().Shift1.ShiftId;
                                    var test = db.shift.Where(s => s.ShiftId == gC).FirstOrDefault();
                                    startTime2 = test.start_time.ToString("hh:mm tt");
                                    shiftEnd3 = test.start_time.AddSeconds(test.shift_end).AddMinutes(30).ToString("hh:mm tt");
                                }
                            }
                        }
                        if (log.final_remarks != "AB")
                        {
                            if (log.time_out != null && shiftEnd3 != "")
                            {
                                string TimeOutUser = log.time_out.Value.ToString("hh:mm tt");
                                DateTime dateTime1 = DateTime.ParseExact(shiftEnd3, "hh:mm tt", CultureInfo.InvariantCulture);
                                DateTime dateTime2 = DateTime.ParseExact(TimeOutUser, "hh:mm tt", CultureInfo.InvariantCulture);


                                if (dateTime1.TimeOfDay < dateTime2.TimeOfDay)
                                {
                                    time = TimeSpan.FromSeconds(log.overtime);
                                    OvertimeNew = time.ToString(@"hh\:mm\:ss");

                                }
                                else
                                {
                                    time = TimeSpan.FromSeconds(log.overtime);
                                    OvertimeNew = "-"; // +time.ToString(@"hh\:mm\:ss");
                                }

                            }
                        }
                        else
                        {
                            time = TimeSpan.FromSeconds(log.overtime);
                            OvertimeNew = "-"; // +time.ToString(@"hh\:mm\:ss");
                        }

                        if (log.overtime_status == 1) { OvertimeStatusNew = "Unapproved"; }
                        else if (log.overtime_status == 2) { OvertimeStatusNew = "Approved"; }
                        else if (log.overtime_status == 3) { OvertimeStatusNew = "Discard"; }
                        toReturn.Add(new ViewModels.MonthlyTimesheetAttendanceLog()
                        {
                            id = log.id,
                            date = (log.date.HasValue) ? log.date.Value.ToString("dd-MM-yyyy") : "",
                            employee_code = log.employee_code,
                            employee_first_name = log.employee_first_name,
                            employee_last_name = log.employee_last_name,
                            time_in = (log.time_in.HasValue) ? log.time_in.Value.ToString("hh:mm tt") : "",
                            status_in = log.status_in,
                            time_out = (log.time_out.HasValue) ? log.time_out.Value.ToString("hh:mm tt") : "",
                            status_out = log.status_out,
                            final_remarks = log.final_remarks,
                            terminal_in = log.terminal_in,
                            terminal_out = log.terminal_out,
                            overtime = log.overtime,
                            overtime_status = OvertimeStatusNew,
                            str_overtime = OvertimeNew,
                            action =
                                @"<div data-id='" + log.id + @"'>
                                <a href='javascript:void(editStatus(" + log.id + "," + log.overtime_status + @"));'>Edit</a>
                            </div>"
                        });
                    }
                }
                return count;
            }
        }

