        private static CultureInfo DayNameCultureForUiLanguage(string uiLanguage)
        {
            if (!string.IsNullOrEmpty(uiLanguage) && uiLanguage.Equals("En", StringComparison.OrdinalIgnoreCase))
                return CultureInfo.GetCultureInfo("en-US");
            if (!string.IsNullOrEmpty(uiLanguage) && uiLanguage.Equals("Ar", StringComparison.OrdinalIgnoreCase))
                return CultureInfo.GetCultureInfo("ar-SA");
            return CultureInfo.CurrentCulture;
        }

        private static string FormatDayNameForGrid(DateTime? dt, string uiLanguage)
        {
            if (!dt.HasValue) return "";
            return dt.Value.ToString("dddd", DayNameCultureForUiLanguage(uiLanguage));
        }

        private static string LocalizeAttendanceArabicToEnglish(string text)
        {
            if (string.IsNullOrEmpty(text)) return text;
            return text
                .Replace("عطلة الاسبوع", "Weekend")
                .Replace("غياب", "Absent");
        }

        private static string MaybeLocalizeAttendanceForEnglish(string text, string uiLanguage)
        {
            if (string.IsNullOrEmpty(text) || !string.Equals(uiLanguage, "En", StringComparison.OrdinalIgnoreCase))
                return text;
            return LocalizeAttendanceArabicToEnglish(text);
        }

        private static string MaybeLocalizeStatusDashComposite(string statusIn, string statusOut, string uiLanguage)
        {
            string a = statusIn ?? "";
            string b = statusOut ?? "";
            if (string.IsNullOrWhiteSpace(a) && string.IsNullOrWhiteSpace(b))
                return "";
            if (string.IsNullOrWhiteSpace(b))
                return string.Equals(uiLanguage, "En", StringComparison.OrdinalIgnoreCase) ? MaybeLocalizeAttendanceForEnglish(a, uiLanguage) : a;
            if (string.IsNullOrWhiteSpace(a))
                return string.Equals(uiLanguage, "En", StringComparison.OrdinalIgnoreCase) ? MaybeLocalizeAttendanceForEnglish(b, uiLanguage) : b;
            if (!string.Equals(uiLanguage, "En", StringComparison.OrdinalIgnoreCase))
                return a + "-" + b;
            return MaybeLocalizeAttendanceForEnglish(a, uiLanguage) + "-" + MaybeLocalizeAttendanceForEnglish(b, uiLanguage);
        }

