        public static int getMonthlyDepartmentalTimesheetReport(int department_id, int designationId, int regionId, int locationId, int functionId, string month, string search, string sortOrder, int start, int length, out List<ViewModels.MonthlyTimesheetAttendanceLog> toReturn)
