                                            EntityFunctions.CreateTime(p.time_in.Value.Hour, p.time_in.Value.Minute, p.time_in.Value.Second).ToString().Contains(search.ToLower()) ||
                                            EntityFunctions.CreateTime(p.time_out.Value.Hour, p.time_out.Value.Minute, p.time_out.Value.Second).ToString().Contains(search.ToLower()) ||
                                            p.terminal_out.Contains(search.ToLower()))
                                            &&
                                            (emp_id.Equals(-1) ||
                                            p.employee.EmployeeId.Equals(emp_id))
                                            &&
                                            (p.date.Value.Year.Equals(monthDate.Year) && p.date.Value.Month.Equals(monthDate.Month))
                                        )
                                    ).Count();

                            temp = db.consolidated_attendance
                                .Where(p => p.active &&

                                        (
                                            (search == null ||
                                            search.Equals("") ||
                                            p.employee.employee_code.Contains(search.ToLower()) ||
                                            p.employee.first_name.Contains(search.ToLower()) ||
                                            p.employee.last_name.Contains(search.ToLower()) ||
                                            p.status_in.Contains(search.ToLower()) ||
                                            p.status_out.Contains(search.ToLower()) ||
                                            p.final_remarks.Contains(search.ToLower()) ||
                                            p.terminal_in.Contains(search.ToLower()) ||
                                            System.Data.Entity.DbFunctions.TruncateTime(p.date).ToString().Contains(search.ToLower()) ||
                                            System.Data.Entity.DbFunctions.CreateTime(p.time_in.Value.Hour, p.time_in.Value.Minute, p.time_in.Value.Second).ToString().Contains(search.ToLower()) ||
                                            System.Data.Entity.DbFunctions.CreateTime(p.time_out.Value.Hour, p.time_out.Value.Minute, p.time_out.Value.Second).ToString().Contains(search.ToLower()) ||

                                            p.terminal_out.Contains(search.ToLower()))

                                            &&

                                            (emp_id.Equals(-1) ||
                                            p.employee.EmployeeId.Equals(emp_id))


                                            &&
                                            (p.date.Value.Year.Equals(monthDate.Year) &&
                                    p.date.Value.Month.Equals(monthDate.Month))
                                        )
                                    )
                                .Select(p =>
                                    new ViewModels.MonthlyTimesheetAttendanceLogIntermediate()
                                    {

