                    firstDay = DateTime.ParseExact(DateTime.Now.ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(DateTime.Now.AddDays(1).ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
            }

            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.ConsolidatedAttendanceExport>();

                var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediate>();

                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    //fill count
                    count = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active &&
                                (
                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            ).Count();

                    //fill temp
                    temp = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active &&
                                (
                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            )
                        .Select(p =>
                            new ViewModels.ConsolidatedAttendanceLogIntermediate()
                            {
                                id = p.ConsolidatedAttendanceId,
                                date = p.date,
                                employee_code = p.employee.employee_code,
                                employee_first_name = p.employee.first_name,
                                employee_last_name = p.employee.last_name,
                                employee_department_name = p.employee.department.name,
                                employee_designation_name = p.employee.designation.name,
                                employee_campus_name = p.campusname,
                                time_in = p.time_in,
                                status_in = p.status_in,
                                time_out = p.time_out,
                                status_out = p.status_out,
                                final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks,
                                description = p.description,
                                terminal_in = (p.terminal_in != null) ? p.terminal_in : " ",
                                terminal_out = (p.terminal_out != null) ? p.terminal_out : " "

                            }).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException)
                {
                    toReturn = new List<ViewModels.ConsolidatedAttendanceExport>();
                }

                List<LeaveApplication> lApplication = new List<LeaveApplication>();
                if (firstDay.HasValue && lastDay.HasValue)
                {
                    lApplication = db.leave_application.Where(l => l.IsActive && l.EmployeeId == emp_id && l.FromDate >= firstDay.Value && l.ToDate <= lastDay.Value).ToList();
                }
                string newfinalremarks = "";
                string startTime2 = "", shiftEnd3 = ""; string timein = ""; string timeout = "";
                string hours = ""; string hours1 = ""; string halfhours1 = ""; TimeSpan duration; TimeSpan duration1; TimeSpan half;
                string halfhours = "";
                var enUs = CultureInfo.GetCultureInfo("en-US");
                foreach (var log in temp)
                {
                    newfinalremarks = log.final_remarks;
                    if (log.final_remarks == "PLO" || log.final_remarks == "PLE" || log.final_remarks == "PLO" || log.final_remarks == "POE" || log.final_remarks == "PLO") { newfinalremarks = "L&E"; }
                    if (log.final_remarks == "PLM" || log.final_remarks == "PME" || log.final_remarks == "POM") { newfinalremarks = "MissPunch"; }

                    int empId = Convert.ToInt32(employee_id);

                    hours = "";
                    halfhours = "";
                    var getGroupId = db.employee.Where(e => e.EmployeeId == empId).FirstOrDefault();
                    if (getGroupId != null)
                    {
                        if (getGroupId.Group != null)
                        {
                            if (getGroupId.Group.follows_general_calendar)
                            {
                                int gC = db.general_calender.Where(s => s.year == DateTime.Now.Year).FirstOrDefault().Shift1.ShiftId;
                                var test = db.shift.Where(s => s.ShiftId == gC).FirstOrDefault();
                                startTime2 = test.start_time.ToString("hh:mm tt", enUs);
                                shiftEnd3 = test.start_time.AddSeconds(test.shift_end).AddMinutes(30).ToString("hh:mm tt", enUs);
                                //string start = fromForm.start_time;
                                //string end = fromForm.shift_end;
                                duration = DateTime.Parse(shiftEnd3, enUs).Subtract(DateTime.Parse(startTime2, enUs));
                                hours = duration.ToString(@"hh\:mm\:ss");
                                half = new TimeSpan(duration.Ticks / 2);
                                halfhours = half.ToString(@"hh\:mm\:ss");
                                //int aa = int.Parse(hours);
                            }
                        }
                    }
                    if (log.time_in != null)
                    {
                        timein = (log.time_in.HasValue) ? log.time_in.Value.ToString("hh:mm tt", enUs) : "";
                        timeout = (log.time_out.HasValue) ? log.time_out.Value.ToString("hh:mm tt", enUs) : "";

                        if (timein == "" || timeout == "")
                        { }
                        else
                        {
                            duration1 = DateTime.Parse(timeout, enUs).Subtract(DateTime.Parse(timein, enUs));
                            hours1 = duration1.ToString(@"hh\:mm\:ss");
                            if (!string.IsNullOrEmpty(hours) && !string.IsNullOrEmpty(halfhours)
                                && TimeSpan.TryParse(hours, CultureInfo.InvariantCulture, out TimeSpan tsFullShift)
                                && TimeSpan.TryParse(halfhours, CultureInfo.InvariantCulture, out TimeSpan tsHalfShift))
                            {
                                if (log.final_remarks == "PO")
                                {
                                    if (duration1 < tsFullShift && duration1 > tsHalfShift)
                                    {
                                        newfinalremarks = "L&E";

                                    }
                                }
                                if (duration1 < tsHalfShift)
                                {
                                    newfinalremarks = "HD";
                                }
                            }
                        }
                    }
                    if (lApplication.Count > 0)
                    {
                        for (int i = 0; i < lApplication.Count; i++)
                        {
                            if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 1) { newfinalremarks = "MeL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 2) { newfinalremarks = "CL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 3) { newfinalremarks = "EL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 4) { newfinalremarks = "E.PL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 5) { newfinalremarks = "MaL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 6) { newfinalremarks = "TL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 7) { newfinalremarks = "VL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 8) { newfinalremarks = "MeetL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 9) { newfinalremarks = "HL"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 17) { newfinalremarks = "PO*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 18) { newfinalremarks = "PLO*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 19) { newfinalremarks = "PLE*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 20) { newfinalremarks = "POE*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 21) { newfinalremarks = "OFF*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 22) { newfinalremarks = "OV*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 23) { newfinalremarks = "OM*"; }
                            else if (log.date >= lApplication[i].FromDate && log.date <= lApplication[i].ToDate && lApplication[i].LeaveStatusId == 2 && lApplication[i].LeaveTypeId == 24) { newfinalremarks = "OT*"; }
                        }
                    }
                    string camname = "";
                    if (log.employee_code != null && log.employee_code != "000000")
                    {
                        var campusemp = db.employee.Where(m => m.employee_code.Equals(log.employee_code)).FirstOrDefault();
                        int campusID = campusemp.campus_id;
                        var orgcampus = db.organization_campus.Where(o => o.Id.Equals(campusID)).FirstOrDefault();
                        if (orgcampus.Id != 0)
                        {
                            camname = orgcampus.CampusCode;
                        }
                    }

                    toReturn.Add(new ViewModels.ConsolidatedAttendanceExport()
                    {
                        Date = (log.date.HasValue) ? log.date.Value.ToString("dd-MM-yyyy") : "",
                        Employee_Number = log.employee_code,
                        First_Name = log.employee_first_name,
                        Last_Name = log.employee_last_name,
                        employee_department_name = log.employee_department_name,
                        employee_designation_name = log.employee_designation_name,
                        employee_campus_name = camname,
                        Time_In = (log.time_in.HasValue) ? log.time_in.Value.TimeOfDay.ToString("c") : "",
                        Remarks_In = log.status_in,
                        Time_Out = (log.time_out.HasValue) ? log.time_out.Value.TimeOfDay.ToString("c") : "",
                        Remarks_Out = log.status_out,
                        Final_Remarks = log.final_remarks,
                        //Final_Remarks = log.final_remarks,
                        description = log.description,
                        Device_In = log.terminal_in,
                        Device_Out = log.terminal_out,

                    });
                }

                return count;
            }
        }

