                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    //fill count
                    count = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active &&
                                (
                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            ).Count();

                    //fill temp
                    temp = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active &&
                                (
                                    (emp_id.Equals(-1) ||
                                    p.employee.EmployeeId.Equals(emp_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            )
                        .Select(p =>
                            new ViewModels.ConsolidatedAttendanceLogIntermediate()
                            {
                                id = p.ConsolidatedAttendanceId,
                                date = p.date,
                                employee_code = p.employee.employee_code,
                                employee_first_name = p.employee.first_name,
                                employee_last_name = p.employee.last_name,
                                time_in = p.time_in,
                                status_in = p.status_in,
                                time_out = p.time_out,
                                status_out = p.status_out,
                                final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks,
                                terminal_in = (p.terminal_in != null) ? p.terminal_in : " ",
                                terminal_out = (p.terminal_out != null) ? p.terminal_out : " "

                            }).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException)
                {
                    toReturn = new List<ViewModels.HourlyAttendanceExport>();
                }



                foreach (var log in temp)
                {
                    string TotalHours = "-";
                    if (log.time_in != null && log.time_out != null)
                    {
                        TotalHours = log.time_out.Value.Subtract(log.time_in.Value).ToString();
                    }

                    toReturn.Add(new ViewModels.HourlyAttendanceExport()
                    {
