        public static int getPayrollReportByMonthForEmployee(string emp_code, string salary_month_year, string search, string sortOrder, int start, int length, out List<ViewModels.PayrollReportByMonthLog> toReturn)
        {
            //int emp_id;
            DateTime fromDate = DateTime.Now;
            DateTime toDate = DateTime.Now;

            if (salary_month_year != null)
            {
                fromDate = DateTime.ParseExact(salary_month_year, "yyyy-MM", CultureInfo.InvariantCulture);
                toDate = new DateTime(fromDate.Year, fromDate.Month, System.DateTime.DaysInMonth(fromDate.Year, fromDate.Month), 23, 59, 59);
            }
            else
            {
