                {
                    fromDate = DateTime.ParseExact(DateTime.Now.ToString("yyyy-07"), "yyyy-MM", CultureInfo.InvariantCulture);
                    toDate = new DateTime(fromDate.Year + 1, 6, System.DateTime.DaysInMonth(fromDate.Year + 1, 6), 23, 59, 59);
                }
                else
                {
                    fromDate = DateTime.ParseExact(DateTime.Now.AddYears(-1).ToString("yyyy-07"), "yyyy-MM", CultureInfo.InvariantCulture);
                    toDate = new DateTime(fromDate.Year, 6, System.DateTime.DaysInMonth(fromDate.Year, 6), 23, 59, 59);
