        public static int getAllDepartmentLogs(string department_id, string designation_id, string employeeCode, string location_id, string from, string to, string search, string sortOrder, int start, int length, out List<ViewModels.ConsolidatedAttendanceLog> toReturn)
        {
            DLL.Models.Function fun = new DLL.Models.Function();
            using (Context db = new Context())
            {
                fun = db.employee.Where(c => c.employee_code == employeeCode).FirstOrDefault().function;
            }
            int depart_id;
            int des_id = -1;
            int fun_id = -1;
            int loc_id = -1;
            if (fun != null)
            {
                fun_id = fun.FunctionId;
            }

            if (!int.TryParse(department_id, out depart_id))
            {
                depart_id = -1;
            }
            if (!int.TryParse(designation_id, out des_id))
            {
                des_id = -1;
            }

            if (!int.TryParse(location_id, out loc_id))
            {
                loc_id = -1;
            }
            DateTime? firstDay = null;
            DateTime? lastDay = null;


            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {
                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
                catch
                {

                }
            }
            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();


                var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediate>();

                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    count = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active && p.employee.active &&

                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.final_remarks.Contains(search.ToLower()))

                                    &&
                                    (depart_id.Equals(-1) ||
                                    p.employee.department.DepartmentId.Equals(depart_id))
                                    &&
                                    (des_id.Equals(-1) ||
                                    p.employee.designation.DesignationId.Equals(des_id))
                                     &&
                                    (fun_id.Equals(-1) ||
                                    p.employee.function.FunctionId.Equals(fun_id))
                                      &&
                                    (loc_id.Equals(-1) ||
                                    p.employee.location.LocationId.Equals(loc_id))
                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            ).Count();

                    temp = db.consolidated_attendance
                        .Where(p => p.active && p.employee.timetune_active && p.employee.active &&

                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.final_remarks.Contains(search.ToLower()))

                                    &&

                                    (depart_id.Equals(-1) ||
                                    p.employee.department.DepartmentId.Equals(depart_id))
                                     &&
                                    (des_id.Equals(-1) ||
                                    p.employee.designation.DesignationId.Equals(des_id))
                                     &&
                                    (fun_id.Equals(-1) ||
                                    p.employee.function.FunctionId.Equals(fun_id))
                                      &&
                                    (loc_id.Equals(-1) ||
                                    p.employee.location.LocationId.Equals(loc_id))

                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            )
                        .Select(p =>
                            new ViewModels.ConsolidatedAttendanceLogIntermediate()
                            {

                                id = p.ConsolidatedAttendanceId,
                                date = p.date,
                                employee_code = p.employee.employee_code,
                                employee_first_name = p.employee.first_name,
                                employee_last_name = p.employee.last_name,
                                time_in = p.time_in,
                                status_in = p.status_in,
                                time_out = p.time_out,
                                status_out = p.status_out,
                                final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks,
                                terminal_in = (p.terminal_in != null) ? p.terminal_in : " ",
                                terminal_out = (p.terminal_out != null) ? p.terminal_out : " "


                            })
                        .SortBy(sortOrder).Skip(start).Take(length).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();
                }



                foreach (var log in temp)
                {
                    toReturn.Add(new ViewModels.ConsolidatedAttendanceLog()
                    {
                        id = log.id,
                        date = (log.date.HasValue) ? log.date.Value.ToString("dd-MM-yyyy") : "",
                        employee_code = log.employee_code,
                        employee_first_name = log.employee_first_name,
                        employee_last_name = log.employee_last_name,
                        time_in = (log.time_in.HasValue) ? log.time_in.Value.ToString("HH:mm:ss") : "",
                        status_in = log.status_in,
                        time_out = (log.time_out.HasValue) ? log.time_out.Value.ToString("HH:mm:ss") : "",
                        status_out = log.status_out,
                        final_remarks = log.final_remarks,
                        terminal_in = log.terminal_in,
                        terminal_out = log.terminal_out
                    });
                }
                return count;
            }

        }

