        public static int getAllMissPunchLogs(string department_id, string designation_id, string function_id, string region_id, string employeeCode, string location_id, string from, string to, string search, out List<ViewModels.ConsolidatedAttendanceDepartmentWise> toReturn)
        {
            DLL.Models.Function fun = new DLL.Models.Function();
            using (Context db = new Context())
            {
                fun = db.employee.Where(c => c.employee_code == employeeCode).FirstOrDefault().function;
            }
            int depart_id = -1;
            int des_id = -1;
            int fun_id = -1;
            int reg_id = -1;
            int loc_id = -1;
            if (fun != null)
            {
                fun_id = fun.FunctionId;
            }

            if (!int.TryParse(function_id, out fun_id))
            {
                fun_id = -1;
            }

            if (!int.TryParse(region_id, out reg_id))
            {
                reg_id = -1;
            }

            if (!int.TryParse(department_id, out depart_id))
            {
                depart_id = -1;
            }
            if (!int.TryParse(designation_id, out des_id))
            {
                des_id = -1;
            }

            if (!int.TryParse(location_id, out loc_id))
            {
                loc_id = -1;
            }
            DateTime? firstDay = null;
            DateTime? lastDay = null;


            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {
                try
                {
                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
                catch
                {

                }
            }
            else
            {
                if (depart_id < 0 && des_id < 0 && fun_id < 0 && reg_id < 0 && loc_id < 0)
                {
                    firstDay = DateTime.ParseExact(DateTime.Now.ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(DateTime.Now.AddDays(1).ToString("dd-MM-yyyy"), "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
            }

            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.ConsolidatedAttendanceDepartmentWise>();


                var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediateDepartmentWise>();


                try
                {

                    DateTime? times;
                    string sdd = "";

                    if (search != null && search.Split(':').Count() == 2 && search.Length == 8)
                    {
                        times = DateTime.Parse(search);
                        var pp = times.Value.TimeOfDay.ToString();
                        sdd = pp.Remove(pp.Length - 3);
                    }
                    count = (from ca in db.consolidated_attendance
                             where (
                                 (ca.active == true && ca.employee.timetune_active && ca.employee.active)
                                     &&
                                 (search == null ||
                                 search.Equals("") ||
                                 ca.employee.employee_code.Contains(search.ToLower()) ||
