        public static string getEmployeeIDByEmployeeCode(string emp_code)
        {
            var emp_id = 0;

            try
            {
                using (var db = new Context())
                {
                    emp_id = db.employee.Where(e => e.employee_code == emp_code).FirstOrDefault().EmployeeId;
                }
            }
            catch (Exception ex)
            {
                emp_id = -1;
            }

            return emp_id.ToString();
        }

