        public static List<ViewModels.ConsolidatedAttendanceDepartmentWiseExcelDownload> getAttendanceManualPunchExcelDownload(int depart_id, int des_id, int loc_id, int fun_id, int reg_id, string from, string to)
        {
            List<ViewModels.ConsolidatedAttendanceDepartmentWiseExcelDownload> toReturn = new List<ViewModels.ConsolidatedAttendanceDepartmentWiseExcelDownload>();
            DateTime? firstDay = null;
            DateTime? lastDay = null;
            var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediateDepartmentWise>();
            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {
                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
                catch
                {

                }
            }

            try
            {
                using (var db = new Context())
                {
                    temp = (from ca in db.consolidated_attendance

                            where (
                                (ca.active == true && ca.employee.timetune_active && ca.employee.active)
                                &&
                                 (ca.manualAttendances.Count() > 0)
                                    &&
                                (depart_id.Equals(-1) || ca.employee.department.DepartmentId.Equals(depart_id))
                                     &&
                                (des_id.Equals(-1) || ca.employee.designation.DesignationId.Equals(des_id))
                                     &&
                                (fun_id.Equals(-1) || ca.employee.function.FunctionId.Equals(fun_id))
                                      &&
                                (reg_id.Equals(-1) || ca.employee.region.RegionId.Equals(reg_id))
                                      &&
                                (loc_id.Equals(-1) || ca.employee.location.LocationId.Equals(loc_id))
                                    &&
                                (!firstDay.HasValue || (ca.date.Value >= firstDay.Value && ca.date.Value <= lastDay))
                            )
                            select new ViewModels.ConsolidatedAttendanceLogIntermediateDepartmentWise()
                            {
                                id = ca.ConsolidatedAttendanceId,
                                date = ca.date,
                                employee_code = ca.employee.employee_code,
                                employee_first_name = ca.employee.first_name,
                                employee_last_name = ca.employee.last_name,
                                time_in = ca.time_in,
                                status_in = ca.status_in,
                                time_out = ca.time_out,
                                status_out = ca.status_out,
                                final_remarks = (ca.manualAttendances.Count() > 0) ? ca.final_remarks + "*" : ca.final_remarks,
                                terminal_in = (ca.terminal_in != null) ? ca.terminal_in : " ",
                                terminal_out = (ca.terminal_out != null) ? ca.terminal_out : " ",
                                function = ca.employee.function.name,
                                region = ca.employee.region.name,
                                department = ca.employee.department.name,
                                designation = ca.employee.designation.name,
                                location = ca.employee.location.name
                            }).ToList();
                }
            }
            catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
            {
                toReturn = new List<ViewModels.ConsolidatedAttendanceDepartmentWiseExcelDownload>();
            }
            foreach (var log in temp)
            {
                toReturn.Add(new ViewModels.ConsolidatedAttendanceDepartmentWiseExcelDownload()
                {
                    Date = (log.date.HasValue) ? log.date.Value.ToString("dd-MM-yyyy") : "",
                    Employee_Code = log.employee_code,
                    First_Name = log.employee_first_name,
                    Last_Name = log.employee_last_name,
                    Time_In = (log.time_in.HasValue) ? log.time_in.Value.ToString("hh:mm tt") : "",
                    Remarks_In = log.status_in,
                    Time_Out = (log.time_out.HasValue) ? log.time_out.Value.ToString("hh:mm tt") : "",
                    Remarks_Out = log.status_out,
                    Final_Remarks = log.final_remarks,
                    Device_In = log.terminal_in,
                    Device_Out = log.terminal_out,
                    Function = log.function,
                    Region = log.region,
                    Department = log.department,
                    Designation = log.designation,
                    Location = log.location
                });
            }

            return toReturn;
        }



        public static int getAllPaAttendanceMatching(string final_remarks, string from, string to, string search, string sortOrder, int start, int length, out List<ViewModels.PaAttendanceLog> toReturn)
        {

            DateTime? firstDay = null;
            DateTime? lastDay = null;

            string remarks = (!final_remarks.Equals("") && final_remarks != null) ? final_remarks : " ";
            if (!final_remarks.Equals(""))
                remarks = final_remarks;
            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {

                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
                catch
                {

                }


            }


            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.PaAttendanceLog>();


                var temp = new List<ViewModels.PaAttendanceLogIntermediate>();

                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    #region for Absent
                    if (remarks.Equals("AB"))
                    {
                        count = db.consolidated_attendance
                            .Where(p => p.active &&

                                    (
                                        (search == null ||
                                        search.Equals("") ||
                                        p.employee.employee_code.Contains(search.ToLower()) ||
                                        p.employee.first_name.Contains(search.ToLower()) ||
                                        p.employee.last_name.Contains(search.ToLower()) ||
                                        p.final_remarks.Contains(search.ToLower()))
                                        &&
                                        (!firstDay.HasValue ||
                                        (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                        &&
                                        (p.final_remarks.Equals("AB"))
                                        &&
                                        (p.employee.timetune_active == true && p.employee.active == true && p.active == true)
                                    )
                                ).Distinct().OrderBy(c => c.employee.employee_code).Count();

                        temp = db.consolidated_attendance
                            .Where(p => p.active &&

                                    (
                                        (search == null ||
                                        search.Equals("") ||
                                        p.employee.employee_code.Contains(search.ToLower()) ||
                                        p.employee.first_name.Contains(search.ToLower()) ||
                                        p.employee.last_name.Contains(search.ToLower()) ||
                                        p.status_in.Contains(search.ToLower()) ||
                                        p.status_out.Contains(search.ToLower()) ||
                                        p.final_remarks.Contains(search.ToLower()))

                                        &&
                                        (!firstDay.HasValue ||
                                        (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                         &&
                                        (p.final_remarks.Equals("AB"))
                                         &&
                                        (p.employee.timetune_active == true && p.employee.active == true && p.active == true)
                                    )
                                ).Distinct().OrderBy(c => c.employee.employee_code)
                            .Select(p =>
                                new ViewModels.PaAttendanceLogIntermediate()
                                {

                                    id = p.ConsolidatedAttendanceId,
                                    date = p.date,
                                    employee_code = p.employee.employee_code,
                                    employee_first_name = p.employee.first_name,
                                    employee_last_name = p.employee.last_name,
                                    final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks

                                })
                            .SortBy(sortOrder).Skip(start).Take(length).ToList();
                    }
                    #endregion
                    #region for present
                    else
                    {
                        count = db.consolidated_attendance
                             .Where(p => p.active &&

                                     (
                                         (search == null ||
                                         search.Equals("") ||
                                         p.employee.employee_code.Contains(search.ToLower()) ||
                                         p.employee.first_name.Contains(search.ToLower()) ||
                                         p.employee.last_name.Contains(search.ToLower()) ||
                                         p.final_remarks.Contains(search.ToLower()))
                                         &&
                                         (!firstDay.HasValue ||
                                         (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                         &&
                                         (!p.final_remarks.Equals("AB") && !p.final_remarks.Equals("OFF"))
                                     )
                                 ).Distinct().OrderBy(c => c.employee.employee_code).Count();

                        temp = db.consolidated_attendance
                            .Where(p => p.active &&

                                    (
                                        (search == null ||
                                        search.Equals("") ||
                                        p.employee.employee_code.Contains(search.ToLower()) ||
                                        p.employee.first_name.Contains(search.ToLower()) ||
                                        p.employee.last_name.Contains(search.ToLower()) ||
                                        p.status_in.Contains(search.ToLower()) ||
                                        p.status_out.Contains(search.ToLower()) ||
                                        p.final_remarks.Contains(search.ToLower()))

                                        &&
                                        (!firstDay.HasValue ||
                                        (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                         &&
                                        (!p.final_remarks.Equals("AB") && !p.final_remarks.Equals("OFF"))
                                    )
                                ).Distinct().OrderBy(c => c.employee.employee_code)
                            .Select(p =>
                                new ViewModels.PaAttendanceLogIntermediate()
                                {

                                    id = p.ConsolidatedAttendanceId,
                                    date = p.date,
                                    employee_code = p.employee.employee_code,
                                    employee_first_name = p.employee.first_name,
                                    employee_last_name = p.employee.last_name,
                                    final_remarks = (p.manualAttendances.Count() > 0) ? p.final_remarks + "*" : p.final_remarks

                                })
                            .SortBy(sortOrder).Skip(start).Take(length).ToList();
                    }
                    #endregion
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.PaAttendanceLog>();
                }



                foreach (var log in temp)
                {
                    toReturn.Add(new ViewModels.PaAttendanceLog()
                    {
                        id = log.id,
                        date = (log.date.HasValue) ? log.date.Value.ToString("dd-MMMM-yyyy") : "",
                        employee_code = log.employee_code,
                        employee_first_name = log.employee_first_name,
                        employee_last_name = log.employee_last_name,
                        final_remarks = log.final_remarks
                    });
                }
                return count;
            }
        }

        public static List<ViewModels.ReportPersistentAttendanceLog> getAllPersistentLog()
        {
            using (Context db = new Context())
            {
                List<PersistentAttendanceLog> persistentAttendance = null;
                try
                {
                    persistentAttendance = db.persistent_attendance_log.Where(m => m.active).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    persistentAttendance = new List<PersistentAttendanceLog>();
                }



                List<ViewModels.ReportPersistentAttendanceLog> toReturn = new List<ViewModels.ReportPersistentAttendanceLog>();

                for (int i = 0; i < persistentAttendance.Count(); i++)
                {
                    ViewModels.ReportPersistentAttendanceLog vmPersistentAttendance = new ViewModels.ReportPersistentAttendanceLog();
                    DLL.Models.Employee employee = new DLL.Models.Employee();
                    int id = persistentAttendance[i].PersistentAttendanceLogId;
                    employee = db.employee.Where(m => m.persistent_attendance_log.PersistentAttendanceLogId == id).FirstOrDefault();

                    vmPersistentAttendance.id = persistentAttendance[i].PersistentAttendanceLogId;
                    vmPersistentAttendance.employee_code = employee.employee_code;
                    vmPersistentAttendance.employee_first_name = employee.first_name;
                    vmPersistentAttendance.employee_last_name = employee.last_name;
                    vmPersistentAttendance.date = (persistentAttendance[i].start_time != null && persistentAttendance[i].start_time.HasValue)
                         ? persistentAttendance[i].start_time.Value.Date.ToString("dd-MM-yyyy") : "";

                    vmPersistentAttendance.time_in = (persistentAttendance[i].time_in != null && persistentAttendance[i].time_in.HasValue)
                         ? persistentAttendance[i].time_in.Value.TimeOfDay.ToString("c") : "";

                    vmPersistentAttendance.time_out = (persistentAttendance[i].time_out != null && persistentAttendance[i].time_out.HasValue)
                     ? persistentAttendance[i].time_out.Value.TimeOfDay.ToString("c") : "";

                    toReturn.Add(vmPersistentAttendance);
                }

                return toReturn;
            }
        }

