        public static List<ViewModels.ReportRawAttendanceLog> getAllRawAttendanceLog()
        {
            using (Context db = new Context())
            {
                List<HaTransit> rawAttendance = null;
                try
                {
                    var maxDate = db.ha_transit.OrderByDescending(m => m.C_Date).FirstOrDefault();

                    // check for null, maxdate is null when
                    // there are no entries in HA transit.

                    if (maxDate != null)
                    {
                        DateTime? fromDate = maxDate.C_Date.Value.AddDays(-45);
                        rawAttendance = db.ha_transit.Where(m => m.C_Date >= fromDate).ToList();
                    }
                    else
                    {
                        rawAttendance = new List<HaTransit>();
                    }

                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    rawAttendance = new List<HaTransit>();
                }



                List<ViewModels.ReportRawAttendanceLog> toReturn = new List<ViewModels.ReportRawAttendanceLog>();

                for (int i = 0; i < rawAttendance.Count(); i++)
                {
                    ViewModels.ReportRawAttendanceLog vmRawAttendance = new ViewModels.ReportRawAttendanceLog();
                    DLL.Models.Employee employee = new DLL.Models.Employee();
                    string empCode = rawAttendance[i].C_Unique;
                    employee = db.employee.Where(m => m.employee_code.Equals(empCode)).FirstOrDefault();

                    vmRawAttendance.id = rawAttendance[i].HaTransitId;
                    vmRawAttendance.employee_code = empCode;

                    if (employee != null)
                    {
                        vmRawAttendance.employee_first_name = employee.first_name;
                        vmRawAttendance.employee_last_name = employee.last_name;
                    }
                    else
                    {
                        vmRawAttendance.employee_first_name = "Not Registered";
                        vmRawAttendance.employee_last_name = "Not Registered";
                    }


                    vmRawAttendance.date = (rawAttendance[i].C_Date != null && rawAttendance[i].C_Date.HasValue)
                         ? rawAttendance[i].C_Date.Value.Date.ToString("dd-MM-yyyy") : "";

                    vmRawAttendance.time = rawAttendance[i].C_Time;



                    toReturn.Add(vmRawAttendance);
                }

                return toReturn;
            }
        }


