                    if (maxDate != null)
                    {
                        DateTime? fromDate = maxDate.C_Date.Value.AddDays(-45);

                        count = db.ha_transit.Where(p =>
                                p.C_Date >= fromDate && p.C_Unique != "" &&
                                    (
                                        search == null ||
                                        search.Equals("") ||
                                        p.C_Unique.Contains(search.ToLower()) ||
                                        db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault()
                                        .first_name.Contains(search.ToLower()) ||
                                        db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault()
                                        .last_name.Contains(search.ToLower())
                                    )
                                ).Count();

                        toReturn =

                            db.ha_transit.Where(p =>
                                p.C_Date >= fromDate && p.C_Unique != "" &&
                                    (
                                        search == null ||
                                        search.Equals("") ||
                                        p.C_Unique.Contains(search.ToLower()) ||
                                        db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault()
                                        .first_name.Contains(search.ToLower()) ||
                                        db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault()
                                        .last_name.Contains(search.ToLower())
                                    )
                                )

                            .Select(p =>
                            new ViewModels.ReportRawAttendanceLog()
                            {
                                id = p.HaTransitId,
                                employee_code = p.C_Unique,
                                employee_first_name = db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault().first_name,
                                employee_last_name = db.employee.Where(e => e.active && e.employee_code.Equals(p.C_Unique)).FirstOrDefault().last_name,
                                date = (p.C_Date != null && p.C_Date.HasValue) ? p.C_Date.Value + "" : "",
                                time = p.C_Time
                            })
                        .SortBy(sortOrder).Skip(start).Take(length).ToList();
                    }
                    else
                    {
                        toReturn = new List<ViewModels.ReportRawAttendanceLog>();
                    }
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.ReportRawAttendanceLog>();
                }



                return count;
            }
        }



