        public static int getAllContractualStaffConsolidate(string employee_id, string from, string to, string search, string sortOrder, int start, int length, out List<ViewModels.ConsolidatedAttendanceLog> toReturn)
        {
            int emp_id;
            if (!int.TryParse(employee_id, out emp_id))
            {
                emp_id = -1;
            }


            DateTime? firstDay = null;
            DateTime? lastDay = null;


            if (from != null && to != null && !from.Equals("") && !to.Equals(""))
            {

                try
                {
                    firstDay = DateTime.ParseExact(from, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    lastDay = DateTime.ParseExact(to, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                }
                catch
                {

                }
                /*string[] components = "saf".Split('-');

                int year;
                int mnth;

                if (components.Length == 2)
                {
                    if (int.TryParse(components[0], out year) && int.TryParse(components[1],out mnth))
                    {
                        firstDayOfMonth = new DateTime(year, mnth, 1);
                        lastDayOfMonth = firstDayOfMonth.Value.AddMonths(1).AddDays(-1);
                    }
                }*/

            }


            using (Context db = new Context())
            {
                int count = 0;
                toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();


                var temp = new List<ViewModels.ConsolidatedAttendanceLogIntermediate>();

                //var maxDate = db.consolidated_attendance.OrderByDescending(m => m.date).FirstOrDefault();
                //DateTime? fromDate = maxDate.date.Value.AddDays(-45);

                try
                {
                    count = db.cs_consolidated_log
                        .Where(p => p.active &&

                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.employee.employee_code.Contains(search.ToLower()) ||
                                    p.employee.employee_name.Contains(search.ToLower()) ||
                                    p.remarks.Contains(search.ToLower()) ||
                                    p.terminal_in.Contains(search.ToLower()) ||
                                    p.terminal_out.Contains(search.ToLower()))

                                    &&
                                    (emp_id.Equals(-1) ||
                                    p.employee.ContractualStaffId.Equals(emp_id))


                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            ).Count();

                    temp = db.cs_consolidated_log
                        .Where(p => p.active &&

                                (
                                    (search == null ||
                                    search.Equals("") ||
                                    p.employee.employee_code.Contains(search.ToLower()) ||
                                    p.employee.employee_name.Contains(search.ToLower()) ||
                                    p.remarks.Contains(search.ToLower()) ||
                                    p.terminal_in.Contains(search.ToLower()) ||
                                    p.terminal_out.Contains(search.ToLower()))

                                    &&

                                    (emp_id.Equals(-1) ||
                                    p.employee.ContractualStaffId.Equals(emp_id))


                                    &&
                                    (!firstDay.HasValue ||
                                    (p.date.Value >= firstDay.Value && p.date.Value <= lastDay))
                                )
                            )
                        .Select(p =>
                            new ViewModels.ConsolidatedAttendanceLogIntermediate()
                            {

                                id = p.CS_PersistentLogId,
                                date = p.date,
                                employee_code = p.employee.employee_code,
                                employee_first_name = p.employee.employee_name,
                                time_in = p.time_in,
                                time_out = p.time_out,
                                final_remarks = p.remarks,
                                terminal_in = (p.terminal_in != null) ? p.terminal_in : " ",
                                terminal_out = (p.terminal_out != null) ? p.terminal_out : " "


                            })
                        .SortBy(sortOrder).Skip(start).Take(length).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.ConsolidatedAttendanceLog>();
                }



                foreach (var log in temp)
                {
                    toReturn.Add(new ViewModels.ConsolidatedAttendanceLog()
                    {
                        id = log.id,
                        date = (log.date.HasValue) ? log.date.Value.ToString("dd-MMMM-yyyy") : "",
                        employee_code = log.employee_code,
                        employee_first_name = log.employee_first_name,
                        time_in = (log.time_in.HasValue) ? log.time_in.Value.ToString("HH:mm:ss") : "",
                        time_out = (log.time_out.HasValue) ? log.time_out.Value.ToString("HH:mm:ss") : "",
                        final_remarks = log.final_remarks,
                        terminal_in = log.terminal_in,
                        terminal_out = log.terminal_out
                    });
                }


                return count;
            }
        }

