        public static int getAllAuditLogsMatching(string search, string sortOrder, int start, int length, out List<ViewModels.ReportAuditLog> toReturn)
        {
            if (sortOrder == "" || sortOrder == "description")
            {
                sortOrder = "AuditTrailId desc";
            }

            if (sortOrder == "str_action_code")
            {
                sortOrder = "action_code";
            }

            if (sortOrder == "str_action_code desc")
            {
                sortOrder = "action_code desc";
            }

            if (sortOrder == "str_create_date_adt")
            {
                sortOrder = "create_date_adt";
            }

            if (sortOrder == "str_create_date_adt desc")
            {
                sortOrder = "create_date_adt desc";
            }

            //if (sortOrder == "AuditTrailId")
            //{
            //    sortOrder = "AuditTrailId desc";
            //}

            using (Context db = new Context())
            {
                int count = 0;
                toReturn = null;
                try
                {


                    count = db.audit_trail.Where(p =>
                                (
                                    search == null ||
                                    search.Equals("") ||
                                    p.user_code.ToLower().Contains(search.ToLower()) ||
                                    p.table.ToLower().Contains(search.ToLower()) ||
                                    EntityFunctions.TruncateTime(p.create_date_adt).ToString().Contains(search.ToLower()) ||
                                    //p.create_date_adt.ToString("dd-MMM-yyyy HH:mm:ss.000").ToLower().Contains(search.ToLower()) ||
                                    p.description.ToLower().Contains(search.ToLower())
                                   )
                                ).Count();
                    if (count == 0)
                    {
                        toReturn = new List<ViewModels.ReportAuditLog>();
                    }
                    else
                    {
                        var dbLogs = db.audit_trail.Where(p =>
                                        search == null ||
                                        search.Equals("") ||
                                        p.user_code.ToLower().Contains(search.ToLower()) ||
                                        p.table.ToLower().Contains(search.ToLower()) ||
                                        EntityFunctions.TruncateTime(p.create_date_adt).ToString().Contains(search.ToLower()) ||
                                        //p.create_date_adt.ToString("dd-MMM-yyyy HH:mm:ss.000").ToLower().Contains(search.ToLower()) ||
                                        p.description.ToLower().Contains(search.ToLower()))
                            //.Select(p =>
                            //new ViewModels.ReportAuditLog()
                            //{
                            //    user_code = p.user_code,
                            //    description = p.description,
                            //    AuditTrailId = p.AuditTrailId,
                            //    action_code = p.action_code,
                            //    table = p.table,
                            //    create_date_adt = p.create_date_adt,
                            //    str_create_date_adt = p.create_date_adt.
                            //})
                            .SortBy(sortOrder).Skip(start).Take(length).ToList();

                        if (dbLogs != null && dbLogs.Count > 0)
                        {
                            List<ViewModels.ReportAuditLog> list = new List<ViewModels.ReportAuditLog>();

                            foreach (var al in dbLogs)
                            {
                                string cDate = al.create_date_adt.ToString("dd-MMM-yyyy HH:mm:ss");
                                //string strDesc = (al.description != null && al.description != "") ? al.description.Replace(",", ", ") : "";
                                string aCode = "";
                                if (al.action_code == DLL.Commons.actionCode.insert)
                                {
                                    aCode = "ADDED";
                                }
                                else if (al.action_code == DLL.Commons.actionCode.update)
                                {
                                    aCode = "UPDATED";
                                }
                                else if (al.action_code == DLL.Commons.actionCode.delete)
                                {
                                    aCode = "DELETED";
                                }
                                else
                                {
                                    aCode = "-";
                                }

                                list.Add(new ViewModels.ReportAuditLog()
                                {
                                    user_code = al.user_code,
                                    description = al.user_code + " - " + aCode + " - " + al.table + " - " + al.description,
                                    AuditTrailId = al.AuditTrailId,
                                    action_code = al.action_code,
                                    table = al.table,
                                    //create_date_adt = al.create_date_adt,
                                    str_action_code = aCode,
                                    str_create_date_adt = cDate
                                });
                            }

                            toReturn = list.OrderByDescending(o => o.AuditTrailId).ToList();
                        }
                        else
                        {
                            toReturn = new List<ViewModels.ReportAuditLog>();
                        }
                    }
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.ReportAuditLog>();
                }

                return count;
            }
        }


