                        "final_remarks like 'PLE' or\n" +
                        "final_remarks like 'PME' or\n" +
                        "final_remarks like 'PLM'\n" +
                        "then 1 else 0 end) as PE,\n" +

                         //"sum (\n" +
                         //"case when \n" +
                         //"final_remarks not like 'AB' and \n" +
                         //"final_remarks not like 'OFF' and \n" +
                         //"final_remarks not like 'LV%'\n" +
                         //"then 1 else 0 end ) Present\n" +

                         "sum (\n" +
                        "case when \n" +
                        "final_remarks like 'P%' or \n" +
                        "final_remarks like 'OV' or \n" +
                        "final_remarks like 'OM' or \n" +
                        "final_remarks like 'OD' or \n" +
                        "final_remarks like 'OT' or \n" +
                        "final_remarks like 'POOD' or \n" +
                        "final_remarks like 'ODPO' \n" +
                        "then 1 else 0 end ) Present\n" +

                        "FROM ConsolidatedAttendances co, Employees e\n" +
                        "where employee_code!= '000000' and \n" +
                        "co.employee_EmployeeId=e.EmployeeId and e.Active=1 and \n" +
                        //"e.department_DepartmentId=d.DepartmentId and \n" +
                        "([date] >= @from and [date] <= @to) \n" +
                        " --and employee_EmployeeId  in (SELECT employee_EmployeeId  FROM ConsolidatedAttendances)\n" +
                        //" and (employee_code like @search or first_name like @search or last_name like @search)\n" +
                        "group by co.employee_EmployeeId,employee_code,first_name,last_name,e.department_DepartmentId,e.designation_DesignationId,e.campus_id\n";

                    var results = db.Database.SqlQuery<TestModel>(
                        sql,
                        new SqlParameter("@from", from),
                        new SqlParameter("@to", to)).ToList();

                    count = results.Count();
                    toReturn = results.Select(
                        p => new ViewModels.AttendanceSummaryExport()
                        {
                            Leave = p.LV,
                            OnTime = p.PO,
                            Late = p.PL,
                            Absent = p.AB,
                            EmployeeCode = p.employee_code,
                            First_Name = p.first_name,
                            Last_Name = p.last_name,
                            Department = p.dept_name,
                            Designation = p.desg_name,
                            Institute = p.camp_name,
                            EarlyGone = p.PE,
                            Present = p.Present
                        }).ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    toReturn = new List<ViewModels.AttendanceSummaryExport>();
                }

            }

            return count;
        }
        public static List<ViewModels.UserTracking> getAllUserTrackingRecords(string fdate, string tdate, string empId)
        {
            using (Context db = new Context())
            {
                List<ViewModels.UserTracking> toReturn = new List<ViewModels.UserTracking>();
                List<HaTransit> HTdata = null;
                try
                {
                    if (tdate != null && fdate != null)
                    {
                        DateTime? formDate = DateTime.ParseExact(fdate, "d-M-yyyy", CultureInfo.InvariantCulture);
                        DateTime? toDate = DateTime.ParseExact(tdate, "d-M-yyyy", CultureInfo.InvariantCulture);

                        int Idemp = Convert.ToInt32(empId);
                        if (Idemp > 0)
                        {
                            string empCode = db.employee.Where(e => e.EmployeeId == Idemp).FirstOrDefault().employee_code;
                            HTdata = db.ha_transit.Where(h => DbFunctions.TruncateTime(h.C_Date) >= DbFunctions.TruncateTime(formDate) && DbFunctions.TruncateTime(h.C_Date) <= DbFunctions.TruncateTime(toDate) && h.C_Unique == empCode).ToList();
                        }
                        else return toReturn;

                        if (HTdata.Count != null && HTdata.Count > 0)
                        {
                            var T_data = db.termainal.ToList();
                            string TerminalName = "";

                            if (T_data != null)
                            {
                                for (int i = 0; i < HTdata.Count(); i++)
                                {
                                    var data = T_data.Where(t => t.L_ID == HTdata[i].L_TID).FirstOrDefault();
                                    if (data != null)
                                    {
                                        TerminalName = data.C_Name;
                                    }
                                    else
                                    {
                                        TerminalName = "-";
                                    }
                                    var time = TimeSpan.Parse(HTdata[i].C_Time);
                                    var date = DateTime.MinValue.Add(time);
                                    toReturn.Add(new ViewModels.UserTracking()
                                    {
                                        C_Name = HTdata[i].C_Name,
                                        C_Unique = HTdata[i].C_Unique,
                                        C_Date = HTdata[i].C_Date.Value.ToString("dd-MM-yyyy"),
                                        C_Time = date.ToString("hh:mm tt"),
                                        TerminalName = TerminalName
                                    });
                                }
                            }
                        }
                    }
                }

                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    HTdata = new List<HaTransit>();
                }





                return toReturn;
            }
        }


        public static List<ViewModels.DevicesTracking> getDevicesTrackingList(string date)
        {

            List<ViewModels.DevicesTracking> result = new List<ViewModels.DevicesTracking>();

            if (date != null)
            {
                // DateTime dtOnline = DateTime.ParseExact(date, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                //2018-10-01

                DateTime OBJ = Convert.ToDateTime(date);
                string fordateFormate = "";
                if (OBJ != null)
                {
                    date = OBJ.ToString("dd-MM-yyyy");
                    fordateFormate = OBJ.ToString("MMM-yyyy");
                }

                var to = DateTime.DaysInMonth(OBJ.Year, OBJ.Month);

                DateTime toDate = DateTime.ParseExact(date, "dd-MM-yyyy", CultureInfo.InvariantCulture);

                DateTime fromDate = DateTime.ParseExact(date, "dd-MM-yyyy", CultureInfo.InvariantCulture);


                var dtTo = toDate;//.AddDays(3);
                var dtFrom = toDate.AddDays(to - 1);
                using (Context db = new Context())
                {

                    var haLogs = db.Database.SqlQuery<ViewModels.DevicesTracking>(string.Format("SP_GetHaLogForTracking @fromDate='{0}',@toDate='{1}'", dtTo, dtFrom)).ToList();

                    var TLogs = db.Database.SqlQuery<ViewModels.DevicesTracking2>(string.Format("SP_GetLogForTracking @fromDate='{0}',@toDate='{1}'", dtTo, dtFrom)).ToList();
                    HaTransit haObject = new HaTransit();
                    Terminals terObj = new Terminals();
                    var HaData = db.ha_transit.Where(h => h.C_Date >= dtTo && h.C_Date <= dtFrom).ToList();
                    if (haLogs != null && haLogs.Count > 0 && HaData != null && HaData.Count > 0)
                    {

                        int id = 0;
                        for (int i = 0; i < haLogs.Count; i++)
                        {

                            id = Convert.ToInt32(haLogs[i].L_TID);
                            haObject = HaData.Where(f => f.L_TID == id && f.C_Date >= dtTo && f.C_Date <= dtFrom && f.active != true).FirstOrDefault();
                            terObj = db.termainal.Where(b => b.L_ID == id).FirstOrDefault();
                            if (terObj == null)
                            {
                                terObj = new Terminals();
                                terObj.Id = 0;
                                terObj.C_Name = "Not In List";

                            }
                            if (haObject != null && terObj != null)
                            {

                                result.Add(new ViewModels.DevicesTracking()
                                {
                                    Name = haObject.C_Name,
                                    C_Unique = haObject.C_Unique,
                                    DeviceName = "-",
                                    L_TID = haObject.L_TID,
                                    Status = "Online",
                                    date = fordateFormate,
                                    branchCode = terObj.Id,
                                    branchName = terObj.C_Name
                                });

                            }

                        }
                    }

                    if (TLogs != null)
                    {
                        int id = 0;
                        Terminals terObj2 = new Terminals();
                        for (int i = 0; i < TLogs.Count; i++)
                        {

                            id = Convert.ToInt32(TLogs[i].L_ID);
                            terObj2 = db.termainal.Where(b => b.L_ID == id).FirstOrDefault();
                            if (terObj2 != null)
                            {
                                result.Add(new ViewModels.DevicesTracking()
                                {
                                    Name = "-",
                                    C_Unique = "-",
                                    DeviceName = "-",
                                    L_TID = TLogs[i].L_ID,
                                    Status = "Offline",
                                    date = fordateFormate,
                                    branchCode = terObj2.Id,
                                    branchName = terObj2.C_Name
                                });
                            }

                        }
                    }




                }
            }


            return result;
        }

    }
    public class EmployeeCrud
    {
        public static int InActivePersistentAttendanceLogsEmployees(int emp_id)
        {
            int count = 0;
            using (Context db = new Context())
            {
                string empCode = "";
                empCode = db.employee.Where(e => e.EmployeeId == emp_id).FirstOrDefault().employee_code;

                if (empCode != "")
                {
                    var p_attendance = db.persistent_attendance_log.Where(m => m.employee_code == empCode && m.active == true).FirstOrDefault();
                    if (p_attendance != null)
                    {
                        p_attendance.active = false;
                        db.SaveChanges();

                        count = 1;
                    }
                }
            }

            return count;
        }

        public static int setPassword(int EmpId, string password)
        {
            if (password == null || password == "")
                return 0;

            using (var db = new Context())
            {
                Employee e = db.employee.Where(m => m.active && m.EmployeeId.Equals(EmpId)).FirstOrDefault();

                if (e == null)
                    return 0;

                DLL.Commons.Passwords.setPassword(e, password);

                db.SaveChanges();
                return e.EmployeeId;
            }
        }
        public static string bulkSetPassword(List<string> csvContents)
        {
            try
            {
                using (var db = new Context())
                {
                    foreach (string line in csvContents)
                    {
                        // split the line
                        string[] values = line.Split(',');

                        // check if the split resulted in at least 3 values (columns).

                        if (values == null || values.Length < 2)
                            continue;

                        // Remove unwanted " characters.
                        string employeeCode = values[0].Replace("\"", "");
                        values[1] = values[1].Replace("\"", "");


                        // continue if its the first row (CSV Header line).
                        if (employeeCode == "employeeCode" || employeeCode == "")
                        {
                            continue;
                        }
                        var emp = db.employee.Where(c => c.employee_code == employeeCode).FirstOrDefault();
                        //for (int i = 0; i < 18; i++)
                        //{
                        //Update Employee
                        TimeTune.EmployeeCrud.setPassword(emp.EmployeeId, values[1]);

                    }



                    return "Successfull";
                }


            }

            catch (Exception)
            {
                return "failed";
            }
        }

