                            // query the db for count
                            count = db.employee.Where(m => m.active && m.campus_id == iGVCampusID).Count();

                            // load actual data.
                            employee = db.employee.Where(m => !m.employee_code.Equals("000000") && m.active && m.campus_id == iGVCampusID)
                                .SortBy(sortOrder).Skip(start).Take(length).ToList();
