        public static int Employees_Status(string searchValue, string sortOrder, int start, int length, out List<ViewModels.Employee> toReturn)
        {
            // If sort order does not contain any of the allowed
            // columns, then it must contain the ones that are not allowed.
            // So change sort order to something that is allowed.
            if (!(sortOrder.Contains("first_name") || sortOrder.Contains("last_name") || sortOrder.Contains("employee_code") || sortOrder.Contains("time_tune_status")))
            {
                sortOrder = "first_name";
            }

            if (sortOrder.Contains("time_tune_status"))
            {
                sortOrder = "timetune_active";
            }


            int count = 0;
            using (Context db = new Context())
            {
                List<DLL.Models.Employee> employee = null;
                try
                {

                    if (searchValue != null && !searchValue.Equals(""))
                    {
                        // query the DB for count.
                        count = db.employee.Where(m =>
                        (m.first_name.Contains(searchValue) ||
                        m.last_name.Contains(searchValue) ||
                        m.employee_code.Contains(searchValue) ||
                        ((m.function != null && m.function.name != null) && m.function.name.Contains(searchValue)) ||
                         ((m.department != null && m.department.name != null) && m.department.name.Contains(searchValue)) ||
                          ((m.region != null && m.region.name != null) && m.region.name.Contains(searchValue)) ||
                           ((m.location != null && m.location.name != null) && m.location.name.Contains(searchValue)) ||
                           ((m.grade != null && m.grade.name != null) && m.grade.name.Contains(searchValue)) ||
                        ((m.designation != null && m.designation.name != null) && m.designation.name.Contains(searchValue)))).Count();

                        // load actual content.
                        employee = db.employee.Where(m =>
                        (m.first_name.Contains(searchValue) ||
                        m.last_name.Contains(searchValue) ||
                        m.employee_code.Contains(searchValue) ||
                        m.function.name.Contains(searchValue) ||
                        m.department.name.Contains(searchValue) ||
                        m.region.name.Contains(searchValue) ||
                        m.location.name.Contains(searchValue) ||
                        m.grade.name.Contains(searchValue) ||
                        m.designation.name.Contains(searchValue)))
                        .SortBy(sortOrder).Skip(start).Take(length).ToList();


                    }
                    else
                    {
                        // query the db for count
                        count = db.employee.Count();

                        // load actual data.
                        employee = db.employee
                            .SortBy(sortOrder).Skip(start).Take(length).ToList();
                    }

                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    employee = new List<DLL.Models.Employee>();
                }



                toReturn = new List<ViewModels.Employee>();

                for (int i = 0; i < employee.Count(); i++)
                {
                    ViewModels.Employee employees = new ViewModels.Employee();
                    DLL.Models.Employee currentEmployee = employee[i];

                    string strSkills = "";
                    if (currentEmployee.skills_set != null && currentEmployee.skills_set != "")
                    {

                        string[] bits = currentEmployee.skills_set.Split(',');
                        if (bits.Length > 0)
                        {
                            var skillData = db.skills_set.ToList();
                            if (skillData != null && skillData.Count > 0)
                            {
                                for (int k = 0; k < bits.Length; k++)
                                {
                                    int val = Convert.ToInt32(bits[k]);

                                    var data_skills = skillData.Where(p => p.Id == val).FirstOrDefault();
                                    if (data_skills != null)
                                        strSkills += data_skills.skillname + ", ";
                                }

                                strSkills = strSkills.Trim();
                                strSkills = strSkills.TrimEnd(',');
                            }
                        }
                    }

                    employees.id = currentEmployee.EmployeeId;

                    employees.first_name = currentEmployee.first_name;
                    employees.last_name = currentEmployee.last_name;
                    employees.employee_code = currentEmployee.employee_code;

                    employees.line_manager_code = "-";
                    employees.superline_manager_code = "-";
                    employees.department_name = (currentEmployee.department != null) ? currentEmployee.department.name : "";
                    // employees.time_tune_status = (currentEmployee.timetune_active == true) ? "Active" : "Deactive";

                    if (currentEmployee.Group != null)
                    {
                        int supervisor = currentEmployee.Group.supervisor_id;

                        Employee lineManager = db.employee.Where(m => m.EmployeeId.Equals(supervisor)).FirstOrDefault();
                        if (lineManager != null)
                        {
                            employees.line_manager_code = lineManager.employee_code;
                        }
                    }

                    var s = db.super_line_manager_tagging.Where(m => m.taggedEmployee.EmployeeId == currentEmployee.EmployeeId).FirstOrDefault();
                    if (s != null)
                    {
                        int SLM = s.superLineManager.EmployeeId;
                        Employee SuperLineManger = db.employee.Where(m => m.EmployeeId.Equals(SLM)).FirstOrDefault();
                        employees.superline_manager_code = SuperLineManger.employee_code;
                    }

                    //employees.email = currentEmployee.email;

                    //employees.address = currentEmployee.address;

