                    string strFile03 = (currentEmployee.file_03 != null && currentEmployee.file_03 != "") ? "<span data-row='" + currentEmployee.EmployeeId + "-03'>" +
                                "<a class='waves-effect waves-light text-danger text-center' href=\"javascript:void(popup('" + currentEmployee.file_03 + "'));\">View03</a>" +
                            "</span>" : "<span>-</span>";

                    string strFile04 = (currentEmployee.file_04 != null && currentEmployee.file_04 != "") ? "<span data-row='" + currentEmployee.EmployeeId + "-04'>" +
                                "<a class='waves-effect waves-light text-danger text-center' href=\"javascript:void(popup('" + currentEmployee.file_04 + "'));\">View04</a>" +
                            "</span>" : "<span>-</span>";

                    string strFile05 = (currentEmployee.file_05 != null && currentEmployee.file_05 != "") ? "<span data-row='" + currentEmployee.EmployeeId + "-05'>" +
                               "<a class='waves-effect waves-light text-danger text-center' href=\"javascript:void(popup('" + currentEmployee.file_05 + "'));\">View05</a>" +
                           "</span>" : "<span>-</span>";

                    employees.view_images = "<span>" + strPhoto + " , " + strFile01 + " , " + strFile02 + " , " + strFile03 + " , " + strFile04 + ", " + strFile05 + "</span>";

                    employees.view_profile = "<a href='/HR/EmployeeManagement/UserProfile?user_code=" + currentEmployee.employee_code + "' target='_blank'>View Profile</a>";

                    //employees.time_tune_status = (currentEmployee.timetune_active == true) ? "Active" : "Deactive";



                    employees.time_tune_status = (currentEmployee.timetune_active == true) ? "<span class='badge label-table badge-success'>Active</span>" : "<span class='badge label-table badge-danger'>Deactivated</span>"; ;


                    var data_payroll = db.payroll.Where(p => p.EmployeeId == employees.id).OrderByDescending(p => p.SalaryMonthYear).FirstOrDefault();
                    if (data_payroll != null && data_payroll.SalaryMonthYear != null)
                    {
                        employees.view_payroll = "<a href='/HR/PayrollsManagement/PayrollSetting?user_code=" + currentEmployee.employee_code + "&salary_month=" + data_payroll.SalaryMonthYear.ToString("dd-MM-yyyy") + "' target='_blank'>View Last Payroll</a>";
                    }
                    else
                    {
                        employees.view_payroll = "<a href='/HR/PayrollsManagement/PayrollSetting?user_code=" + currentEmployee.employee_code + "' target='_blank'>View Payroll</a>";
                    }
                    toReturn.Add(employees);
                }

                return count;
            }
        }


        public static List<ViewModels.Employee> getEmpTodaysBirthdays()
        {
            List<Employee> empBirthday = new List<Employee>();
            List<ViewModels.Employee> toReturn = new List<ViewModels.Employee>();
            DateTime todaysDate = DateTime.Now.Date, empActualBirthDate = DateTime.Now.Date, empCurrentYearBirthDate = DateTime.Now.Date;

            using (Context db = new Context())
            {
                try
                {
                    empBirthday = db.employee.Where(e => e.active && e.date_of_birth != null).ToList();
                    if (empBirthday != null && empBirthday.Count > 0)
                    {
                        for (int i = 0; i < empBirthday.Count(); i++)
                        {
                            if (empBirthday[i].date_of_birth.HasValue && empBirthday[i].date_of_birth.Value != null)
                            {
                                empActualBirthDate = empBirthday[i].date_of_birth.Value;//actual birthdate
                                empCurrentYearBirthDate = new DateTime(DateTime.Now.Year, empActualBirthDate.Month, empActualBirthDate.Day);//birthdate by current year
                                if (empCurrentYearBirthDate == todaysDate)
                                {
                                    toReturn.Add(new ViewModels.Employee()
                                    {
                                        first_name = empBirthday[i].first_name + " " + empBirthday[i].last_name,
                                        date_of_birth = todaysDate.ToString("ddd, dd-MM-yyyy"),
                                        birth_date = empCurrentYearBirthDate,
                                        employee_code = empBirthday[i].employee_code

                                    });
                                }
                            }
                        }
                    }
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    empBirthday = new List<Employee>();
                }
            }

            if (toReturn != null && toReturn.Count > 1)
            {
                toReturn = toReturn.OrderBy(o => o.date_of_birth).OrderBy(o => o.employee_code).ToList();
            }

            return toReturn;
        }

