            string strPositionName = "", strSiteName = "";
            string strSkills = "", strCampusCode = "", strCampusName = "", strPShiftName = "", strGenderName = "";
            using (Context db = new Context())
            {
                if (toConvert.skills_set != null && toConvert.skills_set != "")
                {
                    string[] bits = toConvert.skills_set.Split(',');
                    if (bits.Length > 0)
                    {
                        var skillData = db.skills_set.ToList();
                        if (skillData != null && skillData.Count > 0)
                        {
                            for (int k = 0; k < bits.Length; k++)
                            {
                                int val = Convert.ToInt32(bits[k]);

