        public static ViewModels.Employee convertForHR(DLL.Models.Employee toConvert)
        {
            if (toConvert == null)
                return null;

            string strCampusName = "";
            using (Context db = new Context())
            {
                var dbCampusName = db.organization_campus.Where(c => c.Id == toConvert.campus_id).FirstOrDefault();
                strCampusName = dbCampusName != null ? dbCampusName.CampusCode : "";
            }

            ViewModels.Employee toReturn = new ViewModels.Employee();

            toReturn.id = toConvert.EmployeeId;
            toReturn.campus_id = toConvert.campus_id;

            if (toConvert.campus_id == -1)
            {
                toReturn.campus_name = "Super HR Account";
            }
            else
            {
                toReturn.campus_name = strCampusName;
            }

            toReturn.employee_code = toConvert.employee_code;
            toReturn.first_name = toConvert.first_name;
            toReturn.last_name = toConvert.last_name;
            toReturn.father_name = toConvert.father_name;
            toReturn.is_super_hr_str = toConvert.is_super_hr ? "YES" : "No";

            return toReturn;
        }
