        /**
         * This method changes the access group of an employee from one to another.
         * In the process it makes any changes necessary to remove any data inconsistencies
         * that may arise, after simply changing the access group.
         ***/
        public static void changeEmployeeAccessGroup(int newAccessGroupId, Context db, DLL.Models.Employee toUpdateModel)
        {
            // If the access group of an employee has changed from being an EMP to 
            // HR or line manager, then set the group of that employee to null.
            AccessGroup current = toUpdateModel.access_group;
            AccessGroup newAccessGroup = db.access_group.Where(m => m.AccessGroupId.Equals(newAccessGroupId)).FirstOrDefault();


            // Whenever an employee changes access group
            // and if his group id is not null, remove that
            // employee from the group. This will handle the situation
            // if the employee is an EMP or LM currently.
            // But if the emp is a SLM we need to remove all the tagging
            // from the SLM columns.

            // If the current accessgroup != new access group only then proceed.
            if (current != null && newAccessGroup != null && !current.name.Equals(newAccessGroup.name))
            {

                // If the employee is a line manager currently
                // then remove him as the supervisor of the group.
                // then also remove supervisor id of the group
                if (toUpdateModel.access_group.name.Equals(BLL.TimeTuneRoles.ROLE_LM))
                {

                    Group grp = db.group.Where(m => m.supervisor_id.Equals(toUpdateModel.EmployeeId)).FirstOrDefault();
                    if (grp != null)
                    {
                        grp.supervisor_id = 0;
                    }

                }


                if (toUpdateModel.Group != null)
                {


                    // remove this employee from its group
                    toUpdateModel.Group.Employees.Remove(toUpdateModel);

                    // set the cross reference to null.
                    toUpdateModel.Group = null;




                }


                // Remove tagging if the access group currently is
                // SLM.
                if (current.name.Equals(DLL.Commons.Roles.ROLE_SLM))
                {
                    DLL.Models.SLM[] slms =
                        db.super_line_manager_tagging.Where(x =>
                            x.superLineManager.EmployeeId.Equals(toUpdateModel.EmployeeId)).ToArray();

                    db.super_line_manager_tagging.RemoveRange(slms);
                }
            }

            toUpdateModel.access_group = newAccessGroup;
        }

        public static int remove(ViewModels.Employee toRemove)
        {
            using (Context db = new Context())
            {
                DLL.Models.Employee toRemoveModel = db.employee.Find(toRemove.id);

                //db.employee.Remove(toRemoveModel);
                if (toRemoveModel != null)
                {
                    //code set by IR
                    PersistentAttendanceLog persistantLog = db.persistent_attendance_log.Where(m => m.employee_code == toRemoveModel.employee_code).FirstOrDefault();
                    if (persistantLog != null)
                    {
                        persistantLog.active = false;
                    }

                    toRemoveModel.active = false;
                    toRemoveModel.timetune_active = false;

                    db.SaveChanges();
                }
            }

            return toRemove.id;
        }

        public static int remove_OLD_Version_With_ISSUE(ViewModels.Employee toRemove)
        {
            using (Context db = new Context())
            {
                DLL.Models.Employee toRemoveModel = db.employee.Find(toRemove.id);

                //db.employee.Remove(toRemoveModel);

                //IR: ISSUE using PersistentAttendanceLogId Comparison with Employee_Number
                PersistentAttendanceLog persistantLog = db.persistent_attendance_log.Where(m => m.PersistentAttendanceLogId == toRemove.id).FirstOrDefault();

                persistantLog.active = false;
                toRemoveModel.active = false;

                db.SaveChanges();
            }

            return toRemove.id;
        }
    }

    public class GeneralCalendarCrud
    {
        public static ViewModels.GeneralCalendar convert(GeneralCalendar model)
        {
            if (model == null)
                return null;

            // pick only the active logs.
            GeneralCalendarOverride[] generalOverrides = model.calendarOverrides.Where(m => m.active).ToArray();

            ViewModels.GeneralCalendarOverride[] generalOverridesViewModel = new ViewModels.GeneralCalendarOverride[generalOverrides.Length];

            for (int i = 0; i < generalOverridesViewModel.Length; i++)
            {
                string _date = generalOverrides[i].date.Value.ToString("MM/dd/yyyy");
                string _reason = generalOverrides[i].reason;
                string _shift = (generalOverrides[i].Shift == null || (generalOverrides[i].Shift.shift_end == 0 && generalOverrides[i].Shift.early_time == 0)) ? "-1" : generalOverrides[i].Shift.ShiftId + "";
                string _type = (generalOverrides[i].Shift == null || (generalOverrides[i].Shift.shift_end == 0 && generalOverrides[i].Shift.early_time == 0)) ? (generalOverrides[i].isGazettedHoliday) ? "gazetted" : "holiday" : "shift";


                generalOverridesViewModel[i] = new ViewModels.GeneralCalendarOverride()
                {
                    date = _date,
                    reason = _reason,
                    shift = _shift,
                    type = _type
                };

            }


            return new ViewModels.GeneralCalendar()
            {
                id = model.GeneralCalendarId,
                year = model.year,
                Shift = EmployeeShift.convert(model.Shift),
                Shift1 = EmployeeShift.convert(model.Shift1),
                Shift2 = EmployeeShift.convert(model.Shift2),
                Shift3 = EmployeeShift.convert(model.Shift3),
                Shift4 = EmployeeShift.convert(model.Shift4),
                Shift5 = EmployeeShift.convert(model.Shift5),
                Shift6 = EmployeeShift.convert(model.Shift6),
                generalShift = EmployeeShift.convert(model.generalShift),
                generalOverrides = generalOverridesViewModel
            };
        }

