        public static Shift getShift(dynamic id, Context db)
        {
            // It is important for us to pass the
            // Context object, because if we use a
            // new context in here, and the objects that we
            // return are used for assignments to 'public virtual Shift'
            // fields, then the context used for doing that
            // will treat these objects as new and insert them
            // into the database as new shifts.


            Shift toReturn = (id == null) ? null : // return null if null

                    (id == -1) ? // if -1 return holiday

                    // HOLIDAY is a special shift with 
                    // active = false, star_time as 13:00
                    // and all of the other fields are 0
                    // which is not allowed for any shifts
                    // except a holiday shift. Also note that
                    // the id for the holiday shift is not
                    // -1, infact -1 is simply a flag that the
                    // front end uses to tell us that holiday needs
                    // to be assigned over here.
                    db.shift.Where(m =>
                        m.active.Equals(false) &&
                        m.early_time.Equals(0) &&
                        m.day_end.Equals(0)).FirstOrDefault() :

                    db.shift.Find(id); // else return shift

            return toReturn;
        }


        public static ViewModels.GeneralCalendar getCalendarForYear(int year)
        {
            using (Context db = new Context())
            {
                DLL.Models.GeneralCalendar gc = db.general_calender.Where(m => m.active && m.year.Equals(year)).SingleOrDefault();

                return convert(gc);

            }
        }

        public static bool addOrUpdateCalendar(dynamic data)
        {
            using (Context db = new Context())
            {

                int year = data.year;
                //int general_shift = data.general_shift;
                DLL.Models.GeneralCalendar gc = db.general_calender.Where(m => m.active && m.year.Equals(year)).SingleOrDefault();


                /*
                 * data.shift_days[0-6] week days.
                 * for holiday values are -1 (string)
                 * null for none,
                 * and a number for shifts.
                 */
                if (gc == null)
                {

                    DLL.Models.GeneralCalendar cal = new DLL.Models.GeneralCalendar()
                    {
                        year = year,
                        Shift = getShift(data.shift_days[0], db),
                        Shift1 = getShift(data.shift_days[1], db),
                        Shift2 = getShift(data.shift_days[2], db),
                        Shift3 = getShift(data.shift_days[3], db),
                        Shift4 = getShift(data.shift_days[4], db),
                        Shift5 = getShift(data.shift_days[5], db),
                        Shift6 = getShift(data.shift_days[6], db),
                        generalShift = getShift(data.general_shift, db),
                        active = true
                    };








                    foreach (var item in data.general_overrides)
                    {


                        string date = item.date;
                        string type = item.type;


                        // ignore type nones
                        if (type.Equals("none"))
                            continue;

                        string reason = item.reason;
                        int shift = item.shift;

                        Shift toassign = getShift(shift, db);



                        DateTime dt = DateTime.Parse(date).Date;


                        cal.calendarOverrides = new List<GeneralCalendarOverride>();

                        cal.calendarOverrides.Add(new GeneralCalendarOverride()
                        {
                            active = true,
                            isGazettedHoliday = (type.Equals("gazetted")),
                            date = dt,
                            reason = reason,
                            Shift = toassign
                        });



                    }


                    db.general_calender.Add(cal);



                    db.SaveChanges();
                    return true;
                }
                else
                {
                    // Because our shift attributes are specified
                    // using the 'pulic virtual' specifier their models are loaded
                    // only when requested. So we will request 
                    // for all of the shift attributes first,
                    // and then assign values to them. Else
                    // directly assigning does not have an effect
                    var forceLoad = gc.Shift;
                    forceLoad = gc.Shift1;
                    forceLoad = gc.Shift2;
                    forceLoad = gc.Shift3;
                    forceLoad = gc.Shift4;
                    forceLoad = gc.Shift5;
                    forceLoad = gc.Shift6;
                    forceLoad = gc.generalShift;
                    var forceLoad2 = gc.calendarOverrides;

                    // assign values now.
                    gc.year = year;
                    gc.Shift = getShift(data.shift_days[0], db);
                    gc.Shift1 = getShift(data.shift_days[1], db);
                    gc.Shift2 = getShift(data.shift_days[2], db);
                    gc.Shift3 = getShift(data.shift_days[3], db);
                    gc.Shift4 = getShift(data.shift_days[4], db);
                    gc.Shift5 = getShift(data.shift_days[5], db);
                    gc.Shift6 = getShift(data.shift_days[6], db);
                    gc.generalShift = getShift(data.general_shift, db);




                    foreach (var item in data.general_overrides)
                    {


                        string date = item.date;
                        string type = item.type;
                        string reason = item.reason;
                        int shift = int.Parse(item.shift + "");




                        // Search for an already existing override in the gc
                        // for this date.
                        var calendarOverride = gc.calendarOverrides.Where(m =>

                            m.date.Value.Date.Equals(
                                DateTime.Parse(date).Date
                            )


                            ).FirstOrDefault();

                        Shift toassign = getShift(shift, db);

                        // The override already exists
                        if (calendarOverride != null)
                        {

                            calendarOverride.active = (!type.Equals("none"));
                            calendarOverride.isGazettedHoliday = (type.Equals("gazetted"));

                            calendarOverride.reason = reason;
                            calendarOverride.Shift = toassign;


                        }
                        else // The override does not exist.
                        {
                            // ignore nones.
                            if (type.Equals("none"))
                                continue;

                            gc.calendarOverrides.Add(new GeneralCalendarOverride()
                            {
                                active = true,
                                isGazettedHoliday = (type.Equals("gazetted")),
                                date = DateTime.Parse(date).Date,
                                reason = reason,
                                Shift = toassign
                            });
                        }

                    }

                    db.SaveChanges();

                    return true;
                }
            }
        }
    }

