        public static int AddActuallyUpdate(ViewModels.LeaveType obj)
        {
            using (Context db = new Context())
            {
                var applied_leave_list = db.leave_application.Where(l => l.LeaveTypeId == obj.Id).ToList();
                if (applied_leave_list != null && applied_leave_list.Count > 0)
                {
                    //leave type - already in applied use
                    return -3;
                }
                else
                {
                    var leave_type_name = db.leave_type.Where(p => p.Id != obj.Id && p.LeaveTypeText.ToLower() == obj.LeaveTypeText.ToString().ToLower()).FirstOrDefault();
                    if (leave_type_name != null)
                    {
                        //leave type NAME - already in use
                        return -2;
                    }
                    else
                    {
                        var leave_type = db.leave_type.Where(p => !p.IsActive && p.Id == obj.Id).FirstOrDefault();
                        if (leave_type != null)
                        {
                            leave_type.LeaveTypeText = obj.LeaveTypeText;
                            leave_type.LeaveDefaultCount = obj.LeaveDefaultCount;
                            leave_type.LeaveMaxCount = obj.LeaveMaxCount;
                            leave_type.IsActive = true;
                            leave_type.CreateDateTime = DateTime.Now;
                            leave_type.UpdateDateTime = DateTime.Now;
                            db.SaveChanges();

                            return obj.Id;
                        }
                        else
                        {
                            return -1;
                        }
                    }
                }

            }
        }

