        public static int Add(ViewModels.LeaveSession objLeaveSession)
        {
            using (Context db = new Context())
            {
                DateTime dt_start = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionStartDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                DateTime dt_end = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                var data_check_user = db.leave_session.Where(p => p.EmployeeId == objLeaveSession.EmployeeId && (p.SessionStartDate.Day == dt_start.Day && p.SessionStartDate.Month == dt_start.Month && p.SessionStartDate.Year == dt_start.Year) && (p.SessionEndDate.Day == dt_end.Day && p.SessionEndDate.Month == dt_end.Month && p.SessionEndDate.Year == dt_end.Year)).FirstOrDefault();
                if (data_check_user == null)
                {
                    DLL.Models.LeaveSession usstd = new DLL.Models.LeaveSession()
                    {
                        EmployeeId = objLeaveSession.EmployeeId,
                        SessionStartDate = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionStartDate, "dd-MM-yyyy", CultureInfo.InvariantCulture),
                        SessionEndDate = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture),
                        YearId = Convert.ToInt32(DateTime.ParseExact(objLeaveSession.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture).Year),
                        SickLeaves = objLeaveSession.SickLeaves,
                        CasualLeaves = objLeaveSession.CasualLeaves,
                        AnnualLeaves = objLeaveSession.AnnualLeaves,
                        OtherLeaves = objLeaveSession.OtherLeaves,
                        LeaveType01 = objLeaveSession.LeaveType01,
                        LeaveType02 = objLeaveSession.LeaveType02,
                        LeaveType03 = objLeaveSession.LeaveType03,
                        LeaveType04 = objLeaveSession.LeaveType04,
                        LeaveType05 = objLeaveSession.LeaveType05,
                        LeaveType06 = objLeaveSession.LeaveType06,
                        LeaveType07 = objLeaveSession.LeaveType07,
                        LeaveType08 = objLeaveSession.LeaveType08,
                        LeaveType09 = objLeaveSession.LeaveType09,
                        LeaveType10 = objLeaveSession.LeaveType10,
                        LeaveType11 = objLeaveSession.LeaveType11
                    };
                    db.leave_session.Add(usstd);
                    db.SaveChanges();

                    //////////// If Contractual Employee then update Employees table Joining and Leaving Date - 11 June 2020
                    var contr_emp = db.employee.Where(e => e.type_of_employment.TypeOfEmploymentId == 3 && e.EmployeeId == objLeaveSession.EmployeeId).FirstOrDefault();
                    if (contr_emp != null)
                    {
                        contr_emp.date_of_joining = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionStartDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                        contr_emp.date_of_leaving = (DateTime)DateTime.ParseExact(objLeaveSession.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);

                        db.SaveChanges();
                    }

                    return usstd.id;
                }
                else
                {
                    return -1;
                }

            }

        }

