                {
                    LeaveSession toUpdateModel = db.leave_session.Find(toUpdate.id);
                    toUpdateModel.SessionStartDate = (DateTime)DateTime.ParseExact(toUpdate.str_SessionStartDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    toUpdateModel.SessionEndDate = (DateTime)DateTime.ParseExact(toUpdate.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                    toUpdateModel.YearId = Convert.ToInt32(DateTime.ParseExact(toUpdate.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture).Year);

                    toUpdateModel.SickLeaves = toUpdate.SickLeaves;
                    toUpdateModel.CasualLeaves = toUpdate.CasualLeaves;
                    toUpdateModel.AnnualLeaves = toUpdate.AnnualLeaves;
                    toUpdateModel.OtherLeaves = toUpdate.OtherLeaves;

                    toUpdateModel.LeaveType01 = toUpdate.LeaveType01;
                    toUpdateModel.LeaveType02 = toUpdate.LeaveType02;
                    toUpdateModel.LeaveType03 = toUpdate.LeaveType03;
                    toUpdateModel.LeaveType04 = toUpdate.LeaveType04;
                    toUpdateModel.LeaveType05 = toUpdate.LeaveType05;
                    toUpdateModel.LeaveType06 = toUpdate.LeaveType06;
                    toUpdateModel.LeaveType07 = toUpdate.LeaveType07;
                    toUpdateModel.LeaveType08 = toUpdate.LeaveType08;
                    toUpdateModel.LeaveType09 = toUpdate.LeaveType09;
                    toUpdateModel.LeaveType10 = toUpdate.LeaveType10;
                    toUpdateModel.LeaveType11 = toUpdate.LeaveType11;

                    db.SaveChanges();

                    //////////// If Contractual Employee then update Employees table Joining and Leaving Date - 11 June 2020
                    var contr_emp = db.employee.Where(e => e.type_of_employment.TypeOfEmploymentId == 3 && e.EmployeeId == toUpdateModel.EmployeeId).FirstOrDefault();
                    if (contr_emp != null)
                    {
                        contr_emp.date_of_joining = (DateTime)DateTime.ParseExact(toUpdate.str_SessionStartDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);
                        contr_emp.date_of_leaving = (DateTime)DateTime.ParseExact(toUpdate.str_SessionEndDate, "dd-MM-yyyy", CultureInfo.InvariantCulture);

                        db.SaveChanges();
                    }

                    response = 1;
                }
                else
                {
                    response = -1;
                }
            }

            return response;
        }

