                LeaveSession toRemoveModel = db.leave_session.Find(toRemove.id);
                db.leave_session.Remove(toRemoveModel);
                db.SaveChanges();
                return toRemove;
            }

        }


    }

    public class GeoPhencingCrud
    {

        public static int Add(ViewModels.GeoPhencingTerminal toAdd)
        {
            using (Context db = new Context())
            {
                var data_check_user = db.geo_phencing_terminal.Where(p => p.EmployeeId == toAdd.EmployeeId).FirstOrDefault();
                if (data_check_user == null)
                {
                    string lstBranches = "^", lstTerminals = "^";
                    if (toAdd.lstBranches != null && toAdd.lstBranches.Count > 0)
                    {
                        int bCount = 0;
                        //Branches & Terminals List collection
                        foreach (var b in toAdd.lstBranches)
                        {
                            var TerminalCodes = db.termainal.Where(t => t.branch_code == b).ToList();
                            if (TerminalCodes != null && TerminalCodes.Count > 0)
                            {
                                foreach (var tList in TerminalCodes)
                                {
                                    if (bCount == 0)
                                    {
                                        lstBranches += tList.branch_code + "|" + tList.branch_name + "^";

                                        //if (tList.C_Name.Contains(":"))
                                        //    lstBranches += b + "|" + tList.C_Name.Split(':')[0] + "^";
                                        ////else
                                        ////    lstBranches += "-|-^";
                                    }

                                    lstTerminals += tList.L_ID.ToString() + "|" + tList.branch_name + ":" + tList.C_Name.ToLower() + "^";
                                    bCount++;
                                }

                                bCount = 0;
                            }
                            else
                            {
                                //lstBranches += "-|-^";
                                //lstTerminals += "-|-^";
                            }
                        }
                    }

                    DLL.Models.GeoPhencingTerminal term = new DLL.Models.GeoPhencingTerminal()
                    {
                        EmployeeId = toAdd.EmployeeId,
                        BranchesList = lstBranches,
                        TerminalsList = lstTerminals,
                        TrmCreateDate = DateTime.Now
                    };

                    db.geo_phencing_terminal.Add(term);
                    db.SaveChanges();

                    return term.id;
                }
                else
                {
                    return -1;
                }
            }

        }

