    public class UpdateAttendance
    {
        public static void Update(ViewModels.ConsolidatedAttendanceLog toUpdate, string user_code)
        {

            using (Context db = new Context())
            {
                try
                {
                    DateTime? DT = Convert.ToDateTime(toUpdate.date);
                    var HTdata = db.ha_transit.Where(h => DbFunctions.TruncateTime(h.C_Date) == DbFunctions.TruncateTime(DT) && h.C_Unique == toUpdate.employee_code).ToList();
                    if (HTdata != null)
                    {

                        DateTime timeOut = Convert.ToDateTime(toUpdate.time_out);
                        DateTime timeIn = Convert.ToDateTime(toUpdate.time_in);

                        var result = HTdata.OrderByDescending(t => t.C_Time).FirstOrDefault();
                        var result2 = HTdata.OrderBy(t => t.C_Time).FirstOrDefault();

                        List<HaTransit> toRemoveModel = new List<HaTransit>();
                        toRemoveModel = HTdata;
                        foreach (var item in toRemoveModel)
                        {
                            db.ha_transit.Remove(item);
                        }

                        db.SaveChanges();

                        if (result != null && result2 != null)
                        {

                            DLL.Models.HaTransit newAddTimeOut = new DLL.Models.HaTransit()
                            {
                                C_Name = result.C_Name,
                                C_Unique = result.C_Unique,
                                C_Date = result.C_Date,
                                C_Time = timeOut.TimeOfDay.ToString(),
                                L_UID = result.L_UID,
                                active = true,
                                L_TID = result.L_TID
                            };
                            db.ha_transit.Add(newAddTimeOut);

                            DLL.Models.HaTransit newAddTimeIn = new DLL.Models.HaTransit()
                            {
                                C_Name = result2.C_Name,
                                C_Unique = result2.C_Unique,
                                C_Date = result2.C_Date,
                                C_Time = timeIn.TimeOfDay.ToString(),
                                L_UID = result2.L_UID,
                                active = true,
                                L_TID = result2.L_TID
                            };

                            db.ha_transit.Add(newAddTimeIn);
                            db.SaveChanges();



                        }
                        var empId = db.employee.Where(e => e.employee_code == toUpdate.employee_code).FirstOrDefault().EmployeeId;
                        if (empId != null)
                        {
                            BLL.MarkPreviousAttendance.createOrUpdateAttendance(toUpdate.date, toUpdate.date, empId, user_code);
                        }


                    }


                }
                catch (Exception ex)
                {
                    Console.Error.WriteLine(ex);
                }

            }
        }

        public static int add(ViewModels.Function fromForm)
        {
            DLL.Models.Function newFunction = new DLL.Models.Function()
            {
                name = fromForm.name,
                description = fromForm.description,
                active = true
            };

            using (Context db = new Context())
            {
                db.function.Add(newFunction);
                db.SaveChanges();
            }
            return newFunction.FunctionId;
        }

    }

