    public class Bank_CRUD
    {

        public static int add(ViewModels.BankNameInfo fromForm)
        {
            int result = 0;
            DLL.Models.BankName newBank = new DLL.Models.BankName()
            {

                BankNameText = fromForm.BankNameText,
            };

            using (Context db = new Context())
            {
                var data = db.bank_name.Where(p => p.BankNameText == fromForm.BankNameText).FirstOrDefault();
                if (data == null)
                {
                    db.bank_name.Add(newBank);
                    db.SaveChanges();
                    result = 1;
                }
            }
            return result;
        }

        public static List<ViewModels.BankNameInfo> getAll()
        {
            using (Context db = new Context())
            {
                List<BankName> bankSet = null;
                try
                {
                    bankSet = db.bank_name.ToList();
                }
                catch (System.Data.Entity.Core.EntityCommandExecutionException ex)
                {
                    bankSet = new List<BankName>();
                }



                List<ViewModels.BankNameInfo> toReturn = new List<ViewModels.BankNameInfo>();

                for (int i = 0; i < bankSet.Count(); i++)
                {
                    toReturn.Add(new ViewModels.BankNameInfo()
                    {
                        Id = bankSet[i].Id,
                        BankNameText = bankSet[i].BankNameText,
                        action =
                            "<div data-row='" + bankSet[i].Id + "'>" +
                                "<a href=\"javascript:void(editBank(" + bankSet[i].Id + ",'" + bankSet[i].BankNameText + "'));\">Edit</a>" +
                                "<span> / </span>" +
                                "<a href=\"javascript:void(deleteBank(" + bankSet[i].Id + "));\">Delete</a>" +
                            "</div>"
                    });
                }

                return toReturn;
            }
        }

        public static ViewModels.BankNameInfo get(int primaryKey)
        {
            using (Context db = new Context())
            {
                BankName temp = db.bank_name.Where(m => m.Id.Equals(primaryKey)).SingleOrDefault();

                ViewModels.BankNameInfo toReturn = new ViewModels.BankNameInfo();
                toReturn.Id = temp.Id;
                toReturn.BankNameText = temp.BankNameText;
                return toReturn;
            }
        }

        public static void update(ViewModels.BankNameInfo toUpdate)
        {

            using (Context db = new Context())
            {
                BankName toUpdateModel = db.bank_name.Find(toUpdate.Id);
                if (toUpdateModel != null)
                {
                    toUpdateModel.BankNameText = toUpdate.BankNameText;
                    db.SaveChanges();
                }
            }

        }

        public static ViewModels.BankNameInfo remove(ViewModels.BankNameInfo toRemove)
        {

            using (Context db = new Context())
            {
                BankName toRemoveModel = db.bank_name.Find(toRemove.Id);
                if (toRemoveModel != null)
                {
                    db.bank_name.Remove(toRemoveModel);
                    db.SaveChanges();
                    toRemove.BankNameText = toRemoveModel.BankNameText;
                }
                return toRemove;
            }

        }

    }

